const QUIZ_BANK = [
  {"id":"q-aaa-1","dept":"vascular","disease":"aaa","format":"mcq","stem":"A 72-year-old man with a known 4.8 cm infrarenal AAA. Today's US shows 5.2 cm. Asymptomatic, ex-smoker. Most appropriate next step?","options":["Continue 6-monthly surveillance","Switch to 3-monthly surveillance","Refer for elective repair assessment","Repeat in 12 months","Commence doxycycline"],"answer":2,"explanation":"Expansion of 0.8 cm in 6 months (>1 cm/yr) is an independent indication for repair regardless of absolute diameter. Referral for EVAR/open repair planning is appropriate."},
  {"id":"q-aaa-2","dept":"vascular","disease":"aaa","format":"vignette","stem":"78-year-old woman. Sudden back pain, BP 82/50, HR 118. US shows 7 cm aorta with surrounding fluid. Best hemodynamic target while awaiting theater?","options":["MAP >90 with aggressive crystalloid","Permissive hypotension SBP 70–90 mmHg","Vasopressors to MAP 80","SBP <70","Full resuscitation to normotension"],"answer":1,"explanation":"Permissive hypotension (SBP 70–90, conscious, palpable radial) avoids popping the retroperitoneal hematoma and dilutional coagulopathy. Definitive control is in theater."},
  {"id":"q-aaa-3","dept":"vascular","disease":"aaa","format":"flashcard","front":"What is the threshold diameter for elective AAA repair in women?","back":"5.0 cm — women rupture at smaller diameters than men (threshold 5.5 cm). Source: ESVS 2024 / SVS guidelines."},
  {"id":"q-ap-1","dept":"hpb","disease":"ap","format":"mcq","stem":"Which is NOT part of the Glasgow-Imrie criteria for severe acute pancreatitis?","options":["Age > 55","WBC > 15","Amylase > 1000","PaO₂ < 8 kPa","Calcium < 2 mmol/L"],"answer":2,"explanation":"Amylase level does NOT correlate with severity. Glasgow-Imrie: PaO₂, Age, Neutrophils (WBC), Calcium, Renal (urea), Enzymes (LDH), Albumin, Sugar (glucose) — PANCREAS mnemonic."},
  {"id":"q-chol-1","dept":"hpb","disease":"cholecystitis","format":"mcq","stem":"When should laparoscopic cholecystectomy be performed for acute cholecystitis per TG18/CHOCOLATE trial?","options":["Wait 6 weeks","Within 7 days of symptom onset","Only after ERCP","Open cholecystectomy is safer","Percutaneous cholecystostomy first in all"],"answer":1,"explanation":"Early laparoscopic cholecystectomy within 7 days is now standard of care — lower morbidity and shorter total hospital stay (CHOCOLATE trial 2018)."},
  {"id":"q-app-1","dept":"colorectal","disease":"appendicitis","format":"mcq","stem":"Alvarado score 7 in a 24-year-old man with classical features. Most appropriate next step?","options":["CT abdomen","Discharge with safety-net","Surgical assessment + laparoscopic appendectomy","Antibiotics alone","MRI abdomen"],"answer":2,"explanation":"Alvarado ≥7 has high specificity for appendicitis — proceed to surgical assessment. Imaging adds little in young men with classical features."},
  {"id":"q-pud-1","dept":"uppergi","disease":"pud","format":"vignette","stem":"58-year-old man, sudden epigastric pain, free subdiaphragmatic gas on CXR, hemodynamically stable, Boey score 0. Plan?","options":["Conservative only","Laparoscopic omental (Graham) patch repair","Subtotal gastrectomy","Vagotomy + pyloroplasty","Endoscopic clipping"],"answer":1,"explanation":"Laparoscopic Graham patch repair + washout + H. pylori eradication is first-line. Conservative (Taylor regime) only for highly selected stable patients with sealed perforation."},
  {"id":"q-nec-1","dept":"trauma","disease":"necrotising-fasciitis","format":"mcq","stem":"LRINEC score of 9 in a diabetic with rapidly spreading erythema and disproportionate pain. Best management?","options":["MRI first","Broad-spectrum antibiotics and observe 24h","Urgent surgical exploration and aggressive debridement","Hyperbaric oxygen alone","Punch biopsy"],"answer":2,"explanation":"LRINEC ≥8 = high suspicion. NF is a clinical/surgical diagnosis — never delay debridement for imaging. Broad-spectrum antibiotics + early debridement + ITU support."},
  {"id":"q-cp-1","dept":"hpb","disease":"hcc","format":"mcq","stem":"HCC patient: bilirubin 60 μmol/L, albumin 26 g/L, INR 2.0, moderate ascites, grade I encephalopathy. Child-Pugh class?","options":["A","B","C","Cannot determine","Indeterminate"],"answer":2,"explanation":"Bili >50 (3) + Alb <28 (3) + INR 1.7–2.3 (2) + moderate ascites (3) + grade I enceph (2) = 13 → Child-Pugh C. Score 5–6=A, 7–9=B, 10–15=C."},
  {"id":"q-trans-1","dept":"transplant","disease":"liver-tx","format":"flashcard","front":"What are the Milan criteria for liver transplant in HCC?","back":"Single lesion ≤5 cm, OR up to 3 lesions each ≤3 cm, with no extrahepatic spread and no macrovascular invasion. 5-year survival ~70%."},
  {"id":"q-bre-1","dept":"endocrine","disease":"breast-ca","format":"mcq","stem":"Calculate NPI: 2.5 cm tumor, 2 positive nodes, grade 2.","options":["3.4 (excellent)","4.5 (moderate)","5.5 (poor)","6.0 (poor)","Cannot calculate"],"answer":1,"explanation":"NPI = 0.2×size + node stage (0,1,3) + grade = 0.2×2.5 + 2 + 2 = 4.5 → moderate prognostic group (~80% 5-yr survival)."},
  {"id":"q-dissection-1","dept":"vascular","disease":"aortic-dissection","format":"mcq","stem":"55-year-old hypertensive man, tearing chest pain radiating to back, BP discrepancy, widened mediastinum. Most appropriate management?","options":["IV thrombolysis","CT aortogram then emergency cardiac surgery if Type A","Coronary angiography","IV labetalol and outpatient CT","Pericardiocentesis"],"answer":1,"explanation":"Stanford Type A (ascending aorta involved) is a surgical emergency — ~1–2% mortality per hour untreated. CT aortogram confirms, then emergency ascending aortic replacement."},
  {"id":"q-lung-1","dept":"thoracic","disease":"lung-cancer","format":"mcq","stem":"68-year-old ex-smoker. 3 cm RUL NSCLC, T2a N0 M0 (Stage IB), ECOG 1. Best management?","options":["Radical radiotherapy","Lobectomy ± adjuvant chemotherapy","SBRT only","Chemotherapy then reassess","Wedge resection only"],"answer":1,"explanation":"Stage I–II NSCLC with good PS — lobectomy is gold standard. Adjuvant chemotherapy considered for tumors >4 cm (Stage IIA). SBRT for medically inoperable patients."},
  {"id":"q-inguinal-1","dept":"hernia","disease":"inguinal-hernia","format":"flashcard","front":"What is Hesselbach's triangle and what hernia passes through it?","back":"Bounded by inferior epigastric artery (lateral), rectus abdominis (medial), inguinal ligament (inferior). Direct inguinal hernias protrude through this triangle medial to the inferior epigastric artery."},
  {"id":"q-bowel-1","dept":"uppergi","disease":"small-bowel-obstruction","format":"mcq","stem":"67-year-old woman, previous open hysterectomy, colicky pain, vomiting, distension, absolute constipation 24h. Most common cause and first-line management?","options":["Hernia — emergency surgery","Adhesions — NGT + IV fluids ± water-soluble contrast","Malignancy — CT and oncology","Gallstone ileus — surgery","Volvulus — endoscopic decompression"],"answer":1,"explanation":"Adhesions (previous surgery) account for ~60–70% of SBO. Conservative management with NGT, IV fluids. Gastrografin challenge has diagnostic and therapeutic value. Surgery if fails in 24–48h or signs of strangulation."},
  {"id":"q-torsion-1","dept":"urology","disease":"testicular-torsion","format":"mcq","stem":"A 16-year-old presents with sudden severe left scrotal pain, 4 hours duration. Testis is high-riding and tender. Most appropriate management?","options":["Doppler USS then decide","Analgesia and review in 24h","Urgent surgical exploration and bilateral orchidopexy","IV antibiotics for epididymo-orchitis","Urine culture and discharge"],"answer":2,"explanation":"Testicular torsion is a surgical emergency — do not delay for USS if clinical suspicion is high. Viability is >95% if explored within 6h, falls to ~50% at 12h and near zero at 24h. Bilateral orchidopexy at same sitting."},
  {"id":"q-melanoma-1","dept":"softtissue","disease":"melanoma","format":"flashcard","front":"What margin is recommended for a 2 mm Breslow thickness melanoma?","back":"2 cm wide local excision margin. Breslow <1 mm → 1 cm; 1–2 mm → 1–2 cm; >2 mm → 2 cm. SLNB indicated for Breslow ≥0.8 mm or T1b features. (NICE/MSLT guidelines)"},
  {"id":"q-pyloric-1","dept":"pediatric","disease":"pyloric-stenosis","format":"mcq","stem":"A 5-week-old male presents with non-bilious projectile vomiting after every feed. Bloods show Na 136, K 3.0, Cl 88, HCO₃ 32, pH 7.52. Most appropriate next step?","options":["Ramstedt pyloromyotomy immediately","NG feeds and observe","Resuscitation with normal saline + KCl, then Ramstedt pyloromyotomy","Upper GI contrast study first","Proton pump inhibitor"],"answer":2,"explanation":"Pyloric stenosis is a metabolic emergency, not a surgical emergency. Correct hypochloremic hypokalemic metabolic alkalosis with 0.9% NaCl + KCl before surgery. Ramstedt pyloromyotomy after correction."},
  {"id":"q-rcc-1","dept":"urology","disease":"rcc","format":"mcq","stem":"A 58-year-old woman has an incidental 3.8 cm right renal mass, enhancing on CT, suspicious for RCC. No nodal or metastatic disease. Best management?","options":["Active surveillance","Partial nephrectomy (nephron-sparing)","Radical nephrectomy","Ablation (cryotherapy/RFA)","Sunitinib"],"answer":1,"explanation":"T1b RCC (3–7 cm) — partial nephrectomy is preferred over radical when technically feasible, preserving renal function with equivalent oncological outcomes. Ablation for patients unfit for surgery."},
  {"id":"q-ovarian-1","dept":"gynecology","disease":"ovarian-cancer","format":"flashcard","front":"What is the primary surgical goal in advanced ovarian cancer and what outcome does it predict?","back":"Optimal cytoreduction — no residual disease (R0) or <1 cm residual. R0 resection strongly correlates with improved progression-free and overall survival. Primary debulking or interval debulking after NACT."},
  {"id":"q-nec-paed-1","dept":"pediatric","disease":"nec","format":"mcq","stem":"A 28-week premature neonate develops abdominal distension, bloody stools, and pneumatosis intestinalis on AXR (Bell stage II). Initial management?","options":["Immediate laparotomy","NBM, NG decompression, broad-spectrum IV antibiotics, TPN","Contrast enema","Probiotics only","Peritoneal drain only"],"answer":1,"explanation":"Bell stage II NEC — initial management is medical: NBM, NG tube, IV antibiotics (covering gram-negatives and anaerobes), TPN. Surgery (laparotomy or peritoneal drain) for stage III: perforation, deterioration, or failed medical management."},
  {"id":"q-cli-1","dept":"vascular","disease":"cli","format":"mcq","stem":"A 68-year-old smoker has rest pain, a non-healing toe ulcer, and ABI 0.3. Which Rutherford category applies?","options":["Category 1 (mild claudication)","Category 3 (moderate claudication)","Category 4 (rest pain)","Category 5 (minor tissue loss)","Category 6 (major tissue loss)"],"answer":3,"explanation":"Rest pain = Rutherford 4; minor tissue loss (ulcer <digital level) = Rutherford 5; major tissue loss = 6. This patient has rest pain + non-healing toe ulcer → Rutherford 5 (CLI with minor tissue loss)."},
  {"id":"q-carotid-1","dept":"vascular","disease":"carotid","format":"mcq","stem":"A 72-year-old has a 75% symptomatic ICA stenosis (TIA 3 weeks ago). Best management?","options":["Antiplatelet therapy alone","Carotid endarterectomy within 2 weeks","Carotid stenting (CAS) as first choice","Anticoagulation with warfarin","Repeat imaging in 3 months"],"answer":1,"explanation":"NASCET/ECST: symptomatic ICA stenosis ≥50% benefits from CEA. Benefit is greatest when done within 2 weeks of index event (NNT drops from 20 to 5). CAS is second-line for high surgical-risk patients."},
  {"id":"q-dvt-1","dept":"vascular","disease":"dvt","format":"mcq","stem":"A patient with DVT has a Wells score of 5. D-dimer is positive. What is the next step?","options":["Start LMWH and discharge","Compression duplex USS of the leg","CT pulmonary angiography","Thrombophilia screen before anticoagulation","Inpatient thrombolysis"],"answer":1,"explanation":"Positive D-dimer + high Wells pre-test probability → compression duplex USS to confirm DVT before initiating definitive anticoagulation. Do not delay treatment if USS confirms clot."},
  {"id":"q-taa-1","dept":"vascular","disease":"taa","format":"mcq","stem":"At what diameter is elective repair of a descending thoracic aortic aneurysm recommended in a fit patient?","options":["4.5 cm","5.0 cm","5.5 cm","6.0 cm","6.5 cm"],"answer":2,"explanation":"ESVS/SVS guidelines: descending TAA repair threshold is ≥5.5 cm in standard-risk patients. Ascending aorta (cardiac) threshold is ≥5.5 cm (5.0 cm with bicuspid valve or connective tissue disease)."},
  {"id":"q-pad-1","dept":"vascular","disease":"pad","format":"mcq","stem":"A patient has intermittent claudication at 200m. ABI = 0.65. Best initial management?","options":["Urgent bypass surgery","Aorto-bifemoral bypass","Supervised exercise program + antiplatelet + statin","Immediate angioplasty","Amputation"],"answer":2,"explanation":"Mild–moderate claudication (ABI 0.5–0.9, not CLI): first-line = supervised exercise program (improves walking distance >100%), antiplatelet therapy, statin, smoking cessation. Intervention reserved for disabling symptoms or CLI."},
  {"id":"q-mesenteric-isch-1","dept":"vascular","disease":"mesenteric-isch","format":"mcq","stem":"A 78-year-old with AF presents with severe periumbilical pain but a soft abdomen and a white cell count of 18. What is the diagnosis until proven otherwise?","options":["Acute pancreatitis","Aortic dissection","Acute mesenteric ischemia","Perforated peptic ulcer","Bowel obstruction"],"answer":2,"explanation":"Classic presentation: 'pain out of proportion to signs' in an elderly patient with AF (cardioembolic source). Soft abdomen early = ischemia before infarction. CT angiography is the investigation of choice. Early laparotomy if peritonism develops."},
  {"id":"q-varicose-1","dept":"vascular","disease":"varicose-veins","format":"mcq","stem":"A patient has CEAP C4b varicose veins (lipodermatosclerosis). Which treatment is most appropriate?","options":["Compression stockings alone","Endovenous thermal ablation (EVLA/RFA)","Open Trendelenburg + stripping","Foam sclerotherapy only","Conservative management only"],"answer":1,"explanation":"NICE NG168: for CEAP C2–C6 with symptomatic truncal reflux, offer endovenous thermal ablation (EVLA or RFA) as first-line. Foam sclerotherapy is second-line. Open surgery only if endovenous not suitable."},
  {"id":"q-ras-1","dept":"vascular","disease":"renal-artery-stenosis","format":"mcq","stem":"A 55-year-old woman has resistant hypertension and a bruit over the flank. MRA shows 80% right renal artery stenosis. Most likely etiology?","options":["Atherosclerosis","Fibromuscular dysplasia","Takayasu arteritis","Neurofibromatosis","Polyarteritis nodosa"],"answer":1,"explanation":"Fibromuscular dysplasia (FMD) is the most common cause of RAS in young/middle-aged women; shows 'string of beads' on angiography. Atherosclerosis predominates in older patients. FMD: treat with percutaneous transluminal angioplasty (no stent needed)."},
  {"id":"q-pop-aneurysm-1","dept":"vascular","disease":"popliteal-aneurysm","format":"mcq","stem":"A 65-year-old male presents with acute limb ischemia. Duplex shows a 2.8 cm thrombosed popliteal aneurysm. What is the most appropriate management?","options":["Anticoagulation alone","Intra-arterial thrombolysis then bypass","Emergency bypass with aneurysm exclusion","Amputation","Observation"],"answer":1,"explanation":"Thrombosed popliteal aneurysm with acute limb ischemia: catheter-directed thrombolysis (CDT) to clear run-off vessels first, then bypass (vein graft) with aneurysm exclusion. CDT improves run-off and limb salvage rates."},
  {"id":"q-cbt-1","dept":"vascular","disease":"carotid-body-tumour","format":"mcq","stem":"A neck mass at the carotid bifurcation splays the ICA and ECA on imaging. What is it called?","options":["Parotid pleomorphic adenoma","Branchial cyst","Carotid body tumor (Lyre sign)","Lymph node metastasis","Glomus vagale"],"answer":2,"explanation":"'Lyre sign' = splaying of ICA and ECA by a vascular mass at the bifurcation = pathognomonic of carotid body tumor (paraganglioma). 10% bilateral; 10% malignant; 10% familial (SDH mutations). Pre-op embolization reduces intraoperative bleeding."},
  {"id":"q-tos-1","dept":"vascular","disease":"thoracic-outlet","format":"mcq","stem":"A 28-year-old female violinist has unilateral arm pain and paresthesia worse with overhead activity. Adson test is positive. Most likely diagnosis?","options":["Cervical disc herniation","Carpal tunnel syndrome","Thoracic outlet syndrome — neurogenic","Subclavian artery aneurysm","Pancoast tumor"],"answer":2,"explanation":"Neurogenic TOS (95%): compression of brachial plexus between scalene muscles or cervical rib; young females, overhead activities. Adson test (obliteration of radial pulse with neck extension and rotation). Treat: physiotherapy first; surgical decompression (scalenectomy ± first rib) if refractory."},
  {"id":"q-visceral-aneurysm-1","dept":"vascular","disease":"visceral-aneurysm","format":"mcq","stem":"A 35-year-old woman in the third trimester of pregnancy presents with sudden epigastric pain and hemorrhagic shock. CT shows a ruptured splenic artery aneurysm. What is the risk factor?","options":["Hypertension","Portal hypertension","Pregnancy","Atherosclerosis","Pancreatitis"],"answer":2,"explanation":"Splenic artery aneurysm (SAA) is the most common visceral artery aneurysm. Pregnancy dramatically increases rupture risk (estrogen-mediated medial degeneration). Repair threshold: ≥2 cm or symptomatic or pregnant. Emergency: splenectomy ± aneurysmectomy."},
  {"id":"q-vascular-trauma-1","dept":"vascular","disease":"vascular-trauma","format":"mcq","stem":"A stab wound to zone II of the neck causes pulsatile bleeding and expanding hematoma. Immediate next step?","options":["CT angiography","Urgent surgical exploration","Angiography + stenting","Apply tourniquet and observe","MRI neck"],"answer":1,"explanation":"Hard signs of vascular injury (pulsatile/active bleeding, expanding hematoma, bruit/thrill, signs of distal ischemia) = immediate surgical exploration without further imaging. Soft signs → CT angiography. Zone II neck injuries with hard signs go straight to theater."},
  {"id":"q-lymphoedema-1","dept":"vascular","disease":"lymphoedema","format":"mcq","stem":"A 45-year-old woman develops unilateral arm swelling 2 years after axillary node clearance for breast cancer. Stemmer sign is positive. Diagnosis?","options":["Deep vein thrombosis","Cellulitis","Secondary lymphedema","Lipedema","Venous insufficiency"],"answer":2,"explanation":"Positive Stemmer sign (inability to pinch dorsal skin of second toe/finger) = lymphedema. Post-axillary clearance = secondary lymphedema. Treatment: complex decongestive physiotherapy (CDP) — skin care + MLD + bandaging + compression garments. Stemmer negative = lipedema or venous."},
  {"id":"q-cholangitis-1","dept":"hpb","disease":"cholangitis","format":"mcq","stem":"A 70-year-old presents with Charcot's triad and BP 80/50, GCS 13. Correct management sequence?","options":["ERCP immediately","IV antibiotics + fluid resuscitation, then urgent ERCP within 24h","Laparoscopic cholecystectomy today","Percutaneous drainage first","Conservative management only"],"answer":1,"explanation":"Reynolds' pentad (Charcot's triad + shock + confusion) = severe acute cholangitis. Resuscitate first, then urgent biliary drainage (ERCP preferred) within 24h. Antibiotics: piperacillin-tazobactam. Delay ERCP until hemodynamically stable but do not delay >24h."},
  {"id":"q-choledocholithiasis-1","dept":"hpb","disease":"choledocholithiasis","format":"mcq","stem":"Intraoperative cholangiogram during laparoscopic cholecystectomy shows a 6mm CBD stone. Patient is stable. Best next step?","options":["Open CBD exploration","Laparoscopic transcystic CBD exploration","Post-op ERCP","Leave it — likely to pass","Convert to open immediately"],"answer":1,"explanation":"Intraoperative CBD stone in a laparoscopic case: laparoscopic transcystic exploration (wire basket/balloon) is first choice if cystic duct allows. Post-op ERCP is equally valid (2-stage approach). Open CBD exploration reserved for failed laparoscopic attempts or large stones."},
  {"id":"q-pancreatic-cancer-1","dept":"hpb","disease":"pancreatic-cancer","format":"mcq","stem":"A 65-year-old with painless jaundice and weight loss has CT showing a 3cm head of pancreas mass with SMA contact but no encasement. CA 19-9 = 480. What is the resectability status?","options":["Resectable","Borderline resectable","Locally advanced (unresectable)","Metastatic","Requires ERCP to stage"],"answer":1,"explanation":"Borderline resectable pancreatic cancer: tumor contact with SMA ≤180°, abutment of SMV/PV without occlusion. No distant mets. Standard resectable = no major vessel contact. Locally advanced = >180° SMA encasement. Borderline → neoadjuvant chemotherapy (FOLFIRINOX) then reassess."},
  {"id":"q-chronic-pancreatitis-1","dept":"hpb","disease":"chronic-pancreatitis","format":"mcq","stem":"A 48-year-old alcoholic has chronic pancreatitis with a dilated main pancreatic duct (8mm) and chronic pain. What operation offers ductal drainage?","options":["Whipple procedure","Frey procedure","Distal pancreatectomy","Total pancreatectomy","Puestow procedure (lateral pancreaticojejunostomy)"],"answer":4,"explanation":"Puestow (lateral pancreaticojejunostomy) = main duct decompression for dilated MPD (>5–7mm) — fish-mouth opening of duct and side-to-side Roux-en-Y jejunal anastomosis. Frey adds local head coring. Whipple for dominant head mass. Good pain relief in ~70%."},
  {"id":"q-cholangiocarcinoma-1","dept":"hpb","disease":"cholangiocarcinoma","format":"mcq","stem":"Bismuth-Corlette type IIIA hilar cholangiocarcinoma: which segments are involved?","options":["CHD only","CHD + right hepatic duct","CHD + left hepatic duct","CHD + both right and left ducts","Intrahepatic only"],"answer":1,"explanation":"Bismuth-Corlette: I = CHD; II = both hepatic ducts to confluence; IIIa = CHD + right HD (requires right hepatectomy); IIIb = CHD + left HD (requires left hepatectomy); IV = both + secondary radicles. Type IIIa requires right hepatectomy + caudate lobe resection for R0."},
  {"id":"q-icc-1","dept":"hpb","disease":"icc","format":"mcq","stem":"A 55-year-old with PSC and rising CA 19-9 has a 4cm liver mass at the confluence. Most likely diagnosis?","options":["HCC","Metastasis","Intrahepatic cholangiocarcinoma","Liver abscess","Hemangioma"],"answer":2,"explanation":"PSC is the strongest risk factor for cholangiocarcinoma (intrahepatic and hilar). Rising CA 19-9 in PSC = cholangiocarcinoma until proven otherwise. Unlike HCC, ICC does not arise on cirrhosis background; AFP normal; biopsy often needed."},
  {"id":"q-pancreatic-pseudocyst-1","dept":"hpb","disease":"pancreatic-pseudocyst","format":"mcq","stem":"A 6cm pancreatic pseudocyst is found 6 weeks after acute pancreatitis. Patient is asymptomatic. Management?","options":["Immediate surgical drainage","Endoscopic ultrasound-guided cystogastrostomy","Observation — majority resolve spontaneously","Percutaneous drainage","ERCP stenting"],"answer":2,"explanation":"Asymptomatic pseudocyst, regardless of size: observation — ~50% resolve spontaneously within 6 weeks. Intervene if: symptomatic (pain, early satiety), enlarging, infected, or causing biliary/vascular obstruction. EUS-guided drainage is first-line if intervention needed (>90% success)."},
  {"id":"q-portal-hyp-1","dept":"hpb","disease":"portal-hypertension","format":"mcq","stem":"A cirrhotic patient has a first variceal bleed. After initial resuscitation, what is the definitive endoscopic treatment?","options":["Sclerotherapy","Band ligation (EVL)","TIPS","Propranolol alone","Emergency splenectomy"],"answer":1,"explanation":"Acute esophageal variceal hemorrhage: variceal band ligation (EVL) is the endoscopic treatment of choice — superior to sclerotherapy (lower rebleeding, fewer complications). Give terlipressin + prophylactic antibiotics. TIPS if EVL fails or Child-Pugh C."},
  {"id":"q-liver-abscess-1","dept":"hpb","disease":"liver-abscess","format":"mcq","stem":"A 40-year-old returning from India has right upper quadrant pain, fever, and a single 8cm right lobe liver cyst with 'anchovy paste' aspirate. Diagnosis and treatment?","options":["Pyogenic abscess — IV antibiotics + drainage","Amebic abscess — metronidazole","Hydatid cyst — albendazole + surgery","HCC — resection","Simple cyst — aspiration"],"answer":1,"explanation":"Amebic liver abscess (Entameba histolytica): common in tropical/endemic areas; single right lobe abscess; 'anchovy sauce' aspirate; serology positive. Treatment: metronidazole 400–800mg TDS × 5–10 days (highly effective); drainage only if no response or risk of rupture."},
  {"id":"q-gallbladder-ca-1","dept":"hpb","disease":"gallbladder-cancer","format":"mcq","stem":"Incidental T2 gallbladder cancer found after laparoscopic cholecystectomy. What additional surgery is required?","options":["No further surgery","Port site excision only","Liver resection (segments IVb/V) + regional lymphadenectomy","Total hepatectomy","Whipple procedure"],"answer":2,"explanation":"Incidental T2 gallbladder cancer (invasion through muscularis into perimuscular connective tissue): re-resection with segments IVb/V hepatic resection + portal lymphadenectomy + port site excision. T1a: cholecystectomy alone sufficient. T1b: controversial but simple cholecystectomy usually adequate if R0."},
  {"id":"q-liver-mets-1","dept":"hpb","disease":"liver-metastases","format":"mcq","stem":"A patient has 3 colorectal liver metastases (CLM), all in the right lobe, total diameter 5cm, no extrahepatic disease. What determines resectability?","options":["Number of metastases (max 3)","Total diameter <5cm","Adequate future liver remnant (FLR) ≥20–25% in normal liver","Location in right lobe only","CEA level <200"],"answer":2,"explanation":"CLM resectability is defined by: adequate FLR (≥20–25% normal; ≥30–40% post-chemotherapy; ≥40% cirrhotic), R0 achievable, no unresectable extrahepatic disease. Number and size are no longer absolute contraindications. FLR augmentation: portal vein embolization (PVE) if FLR insufficient."},
  {"id":"q-hepatic-adenoma-1","dept":"hpb","disease":"hepatic-adenoma","format":"mcq","stem":"A 32-year-old woman on OCP has a 6cm liver adenoma. Next step?","options":["Observe with surveillance imaging","Discontinue OCP and repeat imaging in 3 months","Immediate resection","Liver biopsy","Transarterial embolization"],"answer":1,"explanation":"Hepatic adenoma: stop OCP first — 70–80% regress. Resect if: >5cm, bleeding, ≥10% β-catenin mutation (malignant potential), male patient (higher malignancy risk), symptomatic. Repeat imaging at 3 months after stopping OCP; if regressing, may continue surveillance."},
  {"id":"q-hydatid-1","dept":"hpb","disease":"hydatid-cyst","format":"mcq","stem":"A 45-year-old shepherd from endemic area has a 10cm liver cyst with daughter cysts and rim calcification. CE3b on WHO classification. Treatment?","options":["Surgery alone","Albendazole alone","PAIR (percutaneous aspiration, injection, reaspiration) + albendazole","Watch and wait","Liver transplant"],"answer":2,"explanation":"WHO CE3b (active, with daughter cysts): PAIR + albendazole is standard for non-complicated accessible cysts. Pre-PAIR albendazole 4 days; inject hypertonic saline or 95% ethanol; continue albendazole 1 month. Surgery for: CE2/CE3b large, biliary communication, inaccessible, failed PAIR."},
  {"id":"q-ipmn-1","dept":"hpb","disease":"ipmn","format":"mcq","stem":"An incidental 3.5cm main duct IPMN (MPD dilation 11mm) with no mural nodule is found in a 68-year-old fit patient. Management?","options":["6-monthly surveillance MRI","Annual CT only","Surgical resection","EUS-FNA for diagnosis","Observation only — low malignancy risk"],"answer":2,"explanation":"Main duct IPMN with MPD ≥10mm = high risk of malignancy (30–70%); surgical resection recommended in fit patients. Branch duct IPMN <3cm without worrisome features: surveillance. Worrisome features triggering EUS/surgery: solid component, MPD ≥5mm, symptoms, rapid growth."},
  {"id":"q-pan-net-1","dept":"hpb","disease":"pan-net","format":"mcq","stem":"A 45-year-old has episodic dizziness, confusion, and diaphoresis that resolve with glucose. Fasting glucose 2.0mmol/L, insulin elevated. Diagnosis?","options":["Type 2 diabetes","Insulinoma","Glucagonoma","VIPoma","Somatostatinoma"],"answer":1,"explanation":"Insulinoma: Whipple's triad (symptoms of hypoglycemia + BSL <2.5mmol/L + relief with glucose). 72-hour fast with insulin/glucose ratio >0.3 confirms. 90% benign, 90% solitary, 90% in pancreas. Localize with EUS (sensitivity 90%). Treat: enucleation if superficial, distal pancreatectomy if in body/tail."},
  {"id":"q-itp-1","dept":"hpb","disease":"itp","format":"mcq","stem":"A 28-year-old woman has ITP with platelet count 12×10⁹/L despite 6 months of steroids and rituximab. Next step?","options":["Increase steroid dose","Splenectomy","Platelet transfusion only","Bone marrow transplant","IVIG alone"],"answer":1,"explanation":"ITP refractory to steroids and rituximab: splenectomy — removes the main site of antiplatelet antibody production and platelet destruction. Response rate ~70–80%. Vaccinate for encapsulated organisms (pneumococcus, meningococcus, Hemophilus) ≥2 weeks pre-op. Platelet transfusion peri-op if count <50."},
  {"id":"q-hereditary-spherocytosis-1","dept":"hpb","disease":"hereditary-spherocytosis","format":"mcq","stem":"A 16-year-old has hereditary spherocytosis with recurrent hemolytic crises, splenomegaly, and gallstones. Hemoglobin 80g/L. Management?","options":["Observation only","Folic acid supplementation alone","Splenectomy + cholecystectomy","Bone marrow transplant","Steroids"],"answer":2,"explanation":"Moderate-severe HS with hemolysis, recurrent crises, splenomegaly: splenectomy is curative (eliminates extravascular hemolysis). Combine with cholecystectomy if gallstones present. Delay until >6 years old (immunological maturity). Post-splenectomy vaccination essential. Folic acid supplementation for all."},
  {"id":"q-splenic-abscess-1","dept":"hpb","disease":"splenic-abscess","format":"mcq","stem":"A 50-year-old with recent endocarditis has fever and left upper quadrant pain. CT shows a 4cm splenic abscess. Treatment?","options":["IV antibiotics alone","Percutaneous drainage + IV antibiotics","Splenectomy","Laparoscopic drainage","Observation"],"answer":1,"explanation":"Splenic abscess: percutaneous CT-guided drainage + IV antibiotics (gram-positive cover for hematogenous source). Splenectomy reserved for: multilocular abscess, failed drainage, ruptured abscess, or associated hematological disease. Causative organisms: Streptococcus, Staphylococcus, gram-negatives."},
  {"id":"q-psc-1","dept":"hpb","disease":"psc","format":"mcq","stem":"A 35-year-old with UC has rising ALP, pruritus, and 'beads on a string' cholangiogram. What complication requires urgent surveillance?","options":["Cirrhosis","Cholangiocarcinoma","Hepatocellular carcinoma","Gallbladder cancer","Portal hypertension"],"answer":1,"explanation":"PSC has 10–15% lifetime risk of cholangiocarcinoma (CCA). Annual MRI/MRCP + serum CA 19-9 surveillance. Rising CA 19-9 in PSC = CCA until proven otherwise. Dominant stricture: brush cytology + FISH. Liver transplant is the only curative option for PSC itself; CCA arising in PSC has poor prognosis."},
  {"id":"q-diverticulitis-1","dept":"colorectal","disease":"diverticulitis","format":"mcq","stem":"A 65-year-old has CT-proven Hinchey II diverticulitis (pericolic abscess 5cm). No peritonitis. Best management?","options":["Emergency laparotomy + Hartmann's","IV antibiotics alone","Percutaneous CT-guided drainage + IV antibiotics","Colonoscopy now","Oral antibiotics and discharge"],"answer":2,"explanation":"Hinchey II (pericolic/pelvic abscess ≥4cm): percutaneous CT-guided drainage + IV antibiotics. Hinchey I (<4cm): IV antibiotics alone. Hinchey III (purulent peritonitis) and IV (fecal peritonitis): emergency laparotomy (Hartmann's or primary anastomosis + defunctioning ileostomy)."},
  {"id":"q-crc-1","dept":"colorectal","disease":"crc","format":"mcq","stem":"A 60-year-old has a T3N1M0 rectal cancer 5cm from the anal verge. After MDT, what is the recommended approach?","options":["Immediate anterior resection","Short-course radiotherapy then surgery","Long-course chemoradiotherapy (LCRT) then surgery 8–12 weeks later","Chemotherapy alone","Abdominoperineal resection without neoadjuvant therapy"],"answer":2,"explanation":"T3N1 mid/low rectal cancer (MRF not threatened, <12cm from AV): long-course CRT (50.4Gy + 5-FU) → surgery 8–12 weeks (MERCURY trial). Short-course RT (5×5Gy) preferred for upper rectal/clearly resectable. APR if sphincter not preservable. CRM involvement → long-course CRT essential."},
  {"id":"q-rectal-prolapse-1","dept":"colorectal","disease":"rectal-prolapse","format":"mcq","stem":"A 72-year-old woman has full-thickness rectal prolapse with fecal incontinence. Fit for surgery. Best procedure?","options":["Delormes procedure","Altemeier procedure (perineal rectosigmoidectomy)","Laparoscopic ventral mesh rectopexy (VMR)","Manual reduction alone","Sigmoid colectomy only"],"answer":2,"explanation":"Laparoscopic ventral mesh rectopexy (VMR, D'Hoore technique): gold standard for fit patients — low recurrence (~3%), preserves continence and obstructed defecation. Perineal procedures (Altemeier, Delormes) for unfit patients — higher recurrence but lower morbidity. Full-thickness prolapse in fit young/middle-aged patient = VMR."},
  {"id":"q-haemorrhoids-1","dept":"colorectal","disease":"haemorrhoids","format":"mcq","stem":"A 45-year-old has grade III hemorrhoids (prolapse requiring manual reduction) causing significant bleeding. Best treatment?","options":["High-fiber diet alone","Rubber band ligation","Hemorrhoidectomy (Milligan-Morgan)","Proctoscopy and reassurance","Stapled hemorrhoidopexy"],"answer":1,"explanation":"Grade III hemorrhoids: rubber band ligation (RBL) is first-line office treatment — effective in ~80% for grades I-III. Hemorrhoidectomy (Milligan-Morgan or Ferguson) for grade IV, failed RBL, or mixed hemorrhoid/skin tags. Stapled hemorrhoidopexy: faster recovery but higher recurrence and risk of SRUS."},
  {"id":"q-anal-fistula-1","dept":"colorectal","disease":"anal-fistula","format":"mcq","stem":"Parks classification: a fistula passing above the puborectalis. Which type?","options":["Intersphincteric","Trans-sphincteric","Suprasphincteric","Extrasphincteric","Superficial"],"answer":2,"explanation":"Parks classification: intersphincteric (passes through internal sphincter, most common 70%); trans-sphincteric (external sphincter); suprasphincteric (above puborectalis, loops over it); extrasphincteric (outside both sphincters, rare). Suprasphincteric = most complex; treatment with seton or advancement flap."},
  {"id":"q-anal-fissure-1","dept":"colorectal","disease":"anal-fissure","format":"mcq","stem":"A 35-year-old has a posterior anal fissure with a sentinel pile for 3 months. GTN 0.4% failed after 8 weeks. Next step?","options":["Increase GTN dose","Lateral internal sphincterotomy immediately","Botulinum toxin injection","Diltiazem cream","Advancement flap"],"answer":2,"explanation":"Chronic anal fissure management ladder: 1st line = topical GTN or diltiazem; 2nd line = botulinum toxin injection (~70% success); 3rd line = lateral internal sphincterotomy (LIS, gold standard surgical option, >95% healing but 5–10% incontinence risk). After failed GTN, Botox is next."},
  {"id":"q-perianal-abscess-1","dept":"colorectal","disease":"perianal-abscess","format":"mcq","stem":"A 40-year-old has a perianal abscess drained in ED. At 6-week review, persistent discharge. Diagnosis?","options":["Recurrent abscess","Fistula-in-ano","Pilonidal sinus","Hidradenitis suppurativa","Infected sebaceous cyst"],"answer":1,"explanation":"Persistent discharge after perianal abscess drainage = fistula-in-ano in ~50% of cases. Cryptoglandular origin: infection tracks from anal gland. MRI pelvis is gold standard to classify fistula and identify any secondary tracts before surgery. Park's classification guides surgical approach."},
  {"id":"q-pilonidal-1","dept":"colorectal","disease":"pilonidal","format":"mcq","stem":"A 24-year-old has a pilonidal sinus with a single midline pit and no abscess. Best primary treatment?","options":["Wide local excision with primary closure","Lay-open (excision)","Pit picking (Bascom procedure)","Karydakis flap","Conservative — shaving and hygiene"],"answer":3,"explanation":"Asymptomatic/simple pilonidal sinus: pit picking (Bascom I) or Lord-Millar procedure — minimal excision of pit, curettage of cavity, excellent healing. Wide local excision has high recurrence if midline closure used. Off-midline closure (Karydakis or Bascom II) for complex/recurrent disease. Karydakis: best evidence for complex cases."},
  {"id":"q-sigmoid-volvulus-1","dept":"colorectal","disease":"sigmoid-volvulus","format":"mcq","stem":"An 80-year-old institutionalised patient has AXR showing a 'coffee bean' sign pointing to the right upper quadrant. No peritonism. Treatment?","options":["Emergency laparotomy","Colonoscopic detorsion","Barium enema reduction","IV antibiotics and NG tube","CT scan then laparotomy"],"answer":1,"explanation":"Sigmoid volvulus without peritonism: colonoscopic (or rigid sigmoidoscopic) detorsion is first-line — success rate 70–90%. Pass flatus tube and leave in place 24–48h to prevent immediate recurrence. Elective sigmoid colectomy should be offered after successful detorsion. Peritonism/ischemia = emergency laparotomy."},
  {"id":"q-caecal-volvulus-1","dept":"colorectal","disease":"caecal-volvulus","format":"mcq","stem":"A 35-year-old has AXR showing a dilated loop pointing to the left upper quadrant with ileocecal obstruction. CT confirms cecal volvulus. Treatment?","options":["Colonoscopic detorsion","Right hemicolectomy","Cecopexy alone","Barium enema","Observation"],"answer":1,"explanation":"Cecal volvulus: colonoscopic detorsion has low success rate (<30%) — right hemicolectomy is the definitive treatment. In hemodynamically stable patients: on-table lavage + primary anastomosis or ileostomy. Cecopexy has high recurrence. Unlike sigmoid volvulus, endoscopic treatment is not reliable."},
  {"id":"q-lbo-1","dept":"colorectal","disease":"large-bowel-obstruction","format":"mcq","stem":"A 70-year-old has acute LBO from sigmoid cancer. CT shows no perforation, cecum 9cm. Best management?","options":["Emergency Hartmann's","Colonic stent (SEMS) as bridge to surgery","Primary resection + anastomosis","Cecostomy","IV fluids and NG tube only"],"answer":1,"explanation":"Acute malignant LBO without perforation/peritonitis + suitable anatomy: SEMS as bridge to elective resection (CREST trial) reduces stoma rate, allows staging and optimization. Emergency surgery reserved for: perforation, ischemia, SEMS not feasible, cecum >12cm (perforation risk). SEMS → 4–6 weeks → elective resection."},
  {"id":"q-uc-surgical-1","dept":"colorectal","disease":"uc-surgical","format":"mcq","stem":"A patient with pancolitis has toxic megacolon (transverse colon 7cm on AXR) not responding to 72h of IV steroids and ciclosporin. Next step?","options":["Continue steroids for another 48h","Infliximab rescue therapy","Emergency colectomy (subtotal colectomy + end ileostomy)","Total proctocolectomy with IPAA","Biologics + steroids combination"],"answer":2,"explanation":"Toxic megacolon not responding to 72h maximal medical therapy (IV steroids ± rescue ciclosporin/infliximab) = emergency subtotal colectomy + end ileostomy (Hartmann pouch). Do NOT perform IPAA acutely — patient unwell, on steroids, septic. Reversal + IPAA electively 3–6 months later. Oxford criteria guide decision."},
  {"id":"q-crohn-surgical-1","dept":"colorectal","disease":"crohn-surgical","format":"mcq","stem":"A Crohn's patient has a 15cm ileal stricture causing SBO. No active inflammation on bloods. Best surgical option?","options":["Resection with wide margins","Strictureplasty (Heineke-Mikulicz)","Balloon dilatation alone","Ileocolonic resection","Hartmann's procedure"],"answer":1,"explanation":"Short (<10cm) fibrous Crohn's stricture: Heineke-Mikulicz strictureplasty (bowel-conserving). Longer strictures: Finney (10–25cm) or Michelassi (>25cm side-to-side). Resection for: failed strictureplasty, active disease/abscess/fistula, malignancy, multiple strictures. Goal: bowel conservation to prevent short bowel syndrome."},
  {"id":"q-anal-cancer-1","dept":"colorectal","disease":"anal-cancer","format":"mcq","stem":"A 55-year-old woman has biopsy-proven T2N0 squamous cell carcinoma of the anal canal. Standard of care?","options":["APR (abdominoperineal resection)","Wide local excision","Nigro protocol: 5-FU + mitomycin C + 50.4Gy radiotherapy","Chemotherapy alone","Palliative care"],"answer":2,"explanation":"Anal SCC (regardless of T stage for N0M0): chemoradiotherapy (Nigro protocol: 5-FU + MMC + 50.4Gy) is the standard of care (ACT II trial). Complete response in ~90%; 5-year survival >80% for T1-T2. Surgery (APR) reserved for residual/recurrent disease after CRT. Preserves sphincter function."},
  {"id":"q-intestinal-fistula-1","dept":"colorectal","disease":"intestinal-fistula","format":"mcq","stem":"Acronym FRIENDS — which factor predicts failure of spontaneous fistula closure?","options":["F = Fistula output >500mL/day","R = Radiation","I = Infection/Inflammation","E = Epithelialization","All of the above"],"answer":4,"explanation":"FRIENDS: Foreign body, Radiation, Infection/IBD, Epithelialization of tract, Neoplasm, Distal obstruction, Short tract (<2cm)/Steroids. Any one of these predicts failure of spontaneous closure. Manage: SNAP (Sepsis control, Nutritional support, Anatomy definition, Planned surgery) before attempting fistula closure."},
  {"id":"q-carcinoid-appendix-1","dept":"colorectal","disease":"carcinoid-appendix","format":"mcq","stem":"Appendiceal NET 1.8cm found at appendectomy. What additional surgery is required?","options":["No further surgery","Right hemicolectomy","Extended right hemicolectomy","Distal pancreatectomy","None — surveillance only"],"answer":1,"explanation":"Appendiceal NET: <1cm = appendectomy alone sufficient (recurrence <2%). 1–2cm: controversial — right hemicolectomy generally recommended (lymph node metastases ~2%). >2cm: right hemicolectomy mandatory (lymph node involvement ~30%). 1.8cm = borderline; most guidelines recommend right hemicolectomy."},
  {"id":"q-mucocele-1","dept":"colorectal","disease":"mucocele-appendix","format":"mcq","stem":"A mucinous appendiceal cyst is found at laparoscopy. What is the critical surgical principle?","options":["Laparoscopic aspiration and lavage","Intact removal without rupture to prevent pseudomyxoma peritonei","Biopsy only","Drain and send cultures","Appendectomy with formal right hemicolectomy always"],"answer":1,"explanation":"Appendiceal mucocele: intact removal without perforation/rupture is essential — spillage of mucin-producing cells causes pseudomyxoma peritonei (PMP), a potentially fatal complication. Laparoscopic handling requires care; some surgeons convert to open. Right hemicolectomy if HAMN or adenocarcinoma on histology."},
  {"id":"q-fap-1","dept":"colorectal","disease":"fap","format":"mcq","stem":"A 20-year-old with FAP has >1000 colorectal polyps and a strong family history of desmoid tumors. Which gene mutation?","options":["BRCA1","MLH1","APC (5q21)","SMAD4","BRAF V600E"],"answer":2,"explanation":"FAP: APC gene mutation (5q21); autosomal dominant. >100 colorectal adenomas; 100% cancer risk by age 40–50 without prophylactic colectomy. AFAP (<100 polyps): attenuated form. Desmoid tumors: 5–15% of FAP, associated with codon >1310 mutations; common post-colectomy. Prophylactic colectomy by age 20."},
  {"id":"q-lynch-1","dept":"colorectal","disease":"lynch","format":"mcq","stem":"Amsterdam II criteria for Lynch syndrome require: 3 relatives with Lynch-associated cancer (CRC/endometrial/urinary), at least how many generations?","options":["1 generation","2 generations","3 generations","4 generations","5 generations"],"answer":1,"explanation":"Amsterdam II: 3 relatives with Lynch-associated cancers; at least 2 successive generations; at least 1 diagnosed before age 50; FAP excluded; tumors verified histologically. Lynch = mismatch repair gene mutations (MLH1, MSH2, MSH6, PMS2). Annual colonoscopy from age 20–25; consider prophylactic hysterectomy."},
  {"id":"q-gastric-ca-1","dept":"uppergi","disease":"gastric-ca","format":"mcq","stem":"A 65-year-old has a T3N1M0 distal gastric cancer. Adequate staging completed. Standard treatment approach in UK?","options":["Surgery alone (D2 gastrectomy)","Perioperative chemotherapy (FLOT) + D2 gastrectomy","Chemoradiotherapy then surgery","Endoscopic submucosal dissection","Palliative chemotherapy"],"answer":1,"explanation":"FLOT protocol (5-FU, leucovorin, oxaliplatin, docetaxel): 4 cycles pre-op + surgery + 4 cycles post-op — standard UK/European practice (FLOT4 trial, superior to ECF/ECX). Surgery: total gastrectomy (proximal/body) or distal gastrectomy with D2 lymphadenectomy. D1+ acceptable if D2 not achievable."},
  {"id":"q-ugib-1","dept":"uppergi","disease":"ugib","format":"mcq","stem":"A Rockford score of 7 for an UGIB patient — what does this indicate?","options":["Low risk — can be discharged","Intermediate risk — outpatient endoscopy","High risk — inpatient endoscopy within 24h","Very high risk — emergency endoscopy","Need CT angiography"],"answer":2,"explanation":"Glasgow-Blatchford Score (GBS): 0 = low risk (safe for outpatient management); ≥1 = hospital admission. Score ≥7 = high risk of needing intervention (endoscopy/surgery). Endoscopy timing: within 24h for most UGIB; immediate (within 12h) if hemodynamically unstable. Pre-endoscopy PPI infusion reduces stigmata of hemorrhage."},
  {"id":"q-oesoph-cancer-1","dept":"uppergi","disease":"oesophageal-cancer","format":"mcq","stem":"A 60-year-old has T3N1M0 mid-esophageal SCC. Performance status WHO 1. Best treatment?","options":["Esophagectomy alone","Definitive chemoradiotherapy (50.4Gy + FOLFOX)","Neoadjuvant CROSS protocol then esophagectomy","Palliative stent","Endoscopic mucosal resection"],"answer":2,"explanation":"CROSS trial (neoadjuvant carboplatin/paclitaxel + 41.4Gy → surgery): 5-year survival 47% vs 33% surgery alone; now standard for resectable T3N+ esophageal cancer. Definitive CRT (without surgery) for SCC where surgery high-risk or patient preference. Surgery: Ivor Lewis (mid/lower third) or 3-phase McKeown esophagectomy."},
  {"id":"q-hiatus-hernia-1","dept":"uppergi","disease":"hiatus-hernia","format":"mcq","stem":"A 70-year-old has a type III (mixed) giant hiatus hernia with 80% of stomach intrathoracic. She has dysphagia and postprandial pain. Indication for repair?","options":["Asymptomatic hernias always require repair","Symptomatic large type II/III hernias require surgical repair","Only type I hernias require repair","Repair only if volvulus has occurred","PPI therapy first for 6 months"],"answer":1,"explanation":"Giant paraesophageal hernias (type II–IV): repair recommended for symptomatic cases — risk of gastric volvulus, incarceration, strangulation. Laparoscopic repair: hernia reduction + crural repair + fundoplication (Nissen or Toupet). Mesh reinforcement for large defects reduces recurrence. Asymptomatic type I (sliding): PPI + surveillance."},
  {"id":"q-achalasia-1","dept":"uppergi","disease":"achalasia","format":"mcq","stem":"High-resolution manometry shows type II achalasia (100% failed peristalsis, panesophageal pressurization). Best treatment in a 40-year-old fit patient?","options":["Calcium channel blockers","Endoscopic Botox injection","Pneumatic balloon dilatation","Laparoscopic Heller myotomy + partial fundoplication","Esophagectomy"],"answer":3,"explanation":"Type II achalasia has the best surgical outcome. Laparoscopic Heller myotomy (LHM) + partial fundoplication (Dor/Toupet): durable relief in 85–90%. POEM (peroral endoscopic myotomy) is equally effective and increasingly preferred. Pneumatic dilatation: good short-term results but ~30% need re-treatment. Botox: temporary (6 months), for unfit patients."},
  {"id":"q-boerhaave-1","dept":"uppergi","disease":"boerhaave","format":"mcq","stem":"A 50-year-old vomited forcefully and presents 4 hours later with chest pain, subcutaneous emphysema, and left pleural effusion. CXR shows pneumomediastinum. Diagnosis and immediate management?","options":["Esophageal foreign body — endoscopy","Boerhaave syndrome — emergency surgery","Aortic dissection — CT aortogram","Tension pneumothorax — needle decompression","Myocardial infarction — ECG and troponin"],"answer":1,"explanation":"Boerhaave syndrome (spontaneous esophageal perforation): Mackler's triad = vomiting + chest pain + subcutaneous emphysema. Confirm with water-soluble contrast swallow or CT. <24h: primary repair + wide drainage. >24h/contamination: esophageal exclusion/diversion or T-tube repair ± esophagectomy for severe cases."},
  {"id":"q-bariatric-1","dept":"uppergi","disease":"bariatric","format":"mcq","stem":"BMI 38 with T2 diabetes, hypertension, and OSA. Patient has tried structured weight management for 2 years. Eligible for bariatric surgery?","options":["No — BMI must be ≥40","Yes — NICE criteria met (BMI ≥35 + obesity-related comorbidities)","Only if BMI >50","Only laparoscopic gastric band eligible","No surgery until BMI >45"],"answer":1,"explanation":"NICE NG28: bariatric surgery for BMI ≥40, OR ≥35 with significant obesity-related comorbidity (T2DM, OSA, HTN, NASH). Also consider ≥30 in South Asian origin with T2DM. Must have completed structured weight management program. RYGB: best evidence for T2DM remission (~80%). SG: simpler, similar weight loss."},
  {"id":"q-gastric-volvulus-1","dept":"uppergi","disease":"gastric-volvulus","format":"mcq","stem":"Borchardt's triad for acute gastric volvulus: which 3 signs?","options":["Epigastric pain + vomiting + melena","Unproductive retching + epigastric pain + inability to pass NGT","Hematemesis + tachycardia + shock","Dysphagia + weight loss + vomiting","Abdominal distension + constipation + vomiting"],"answer":1,"explanation":"Borchardt's triad: (1) unproductive retching/dry heaves, (2) severe epigastric pain, (3) inability to pass NGT into stomach. Classic for acute organoaxial gastric volvulus (60%) associated with para-esophageal hernia. Organoaxial = rotation along long axis. Emergency: NGT decompression if possible, then urgent laparoscopic/open reduction + gastropexy + hiatus repair."},
  {"id":"q-gist-1","dept":"uppergi","disease":"gist","format":"mcq","stem":"A 4cm GIST of the stomach with mitotic rate <5/50HPF. KIT (CD117) positive. Stage and treatment?","options":["Observation only","Wedge resection alone","Wedge resection; imatinib only if R1","Wedge resection + adjuvant imatinib 3 years","Gastrectomy + imatinib"],"answer":1,"explanation":"Gastric GIST >2cm: resection with R0 margins (wedge resection — no need for wide margins or lymphadenectomy, GISTs do not spread via lymphatics). Adjuvant imatinib: for intermediate/high risk (size >5cm OR mitotic rate >5/50HPF). 3cm + low mitotic rate = low risk → surgery alone. High risk = 3 years imatinib."},
  {"id":"q-barretts-1","dept":"uppergi","disease":"barretts","format":"mcq","stem":"Barrett's esophagus with high-grade dysplasia (HGD). No visible lesion on chromoendoscopy. Management?","options":["Esophagectomy","Increased PPI dose and repeat endoscopy in 3 months","Radiofrequency ablation (RFA)","Photodynamic therapy","Continue surveillance only"],"answer":2,"explanation":"Barrett's with HGD (no visible lesion): radiofrequency ablation (RFA) is first-line — 90% complete eradication of HGD, reduces risk of progression to adenocarcinoma. Visible lesion: EMR first then RFA for flat Barrett's. Esophagectomy reserved for submucosal invasion (T1b) or failed endoscopic therapy. Surveillance: 2-yearly if no dysplasia."},
  {"id":"q-zenker-1","dept":"uppergi","disease":"zenker","format":"mcq","stem":"An 80-year-old has regurgitation of undigested food, halitosis, and aspiration pneumonia. Barium swallow shows a posterior pharyngeal pouch at Killian's dehiscence. Treatment of choice?","options":["Open transcervical diverticulectomy","Dohlman procedure (endoscopic stapling)","PPI and observation","Cricopharyngeal myotomy alone","Balloon dilatation"],"answer":1,"explanation":"Zenker's diverticulum: endoscopic stapling (Dohlman/POEM) is now preferred over open surgery in most centers — lower complication rate, shorter hospital stay, equally effective. Mechanism: cricopharyngeal muscle hypertrophy → pulsion diverticulum through Killian's dehiscence. Open transcervical approach for large (>4cm) or failed endoscopic attempts."},
  {"id":"q-caustic-1","dept":"uppergi","disease":"caustic-oesoph","format":"mcq","stem":"A 3-year-old ingested drain cleaner (alkali). Grade IIb Zargar endoscopic injury (deep ulcers, some necrosis). Management?","options":["Immediate esophagectomy","Nasogastric feeding + PPI + strict NPO; surveillance endoscopy at 3 weeks","Barium swallow within 24h","Neutralisation with acidic solution","Steroids only"],"answer":1,"explanation":"Caustic ingestion: NO neutralisation (exothermic reaction). Grade I-IIa: conservative (PPI, fluids, NGT feeding). Grade IIb-III: admission, NGT feeding + PPI, no steroids (no benefit, masking). Esophagectomy if: grade IIIb (full thickness necrosis), perforation, mediastinitis. Long-term: 20% develop stricture within weeks–months; surveillance + dilatation."},
  {"id":"q-meckel-1","dept":"uppergi","disease":"meckel","format":"mcq","stem":"A 4-year-old has painless rectal bleeding. Technetium-99m pertechnetate scan shows uptake at the right iliac fossa. Diagnosis?","options":["Intussusception","Meckel's diverticulum with ectopic gastric mucosa","Appendicitis","Colonic polyp","Juvenile polyp"],"answer":1,"explanation":"Meckel's diverticulum: rule of 2s — 2% population, 2 feet from ileocecal valve, 2 inches long, 2% symptomatic, 2x more common in males, 2 types of ectopic mucosa (gastric > pancreatic). Technetium-99m scan detects ectopic gastric mucosa (sensitivity 85–90% in children). Symptomatic: diverticulectomy or ileal resection."},
  {"id":"q-small-bowel-net-1","dept":"uppergi","disease":"small-bowel-net","format":"mcq","stem":"A 55-year-old has episodic flushing, diarrhea, and right heart valve disease. 24h urinary 5-HIAA is elevated. Diagnosis?","options":["Carcinoid syndrome from midgut NET with liver metastases","VIPoma","Pheochromocytoma","Mastocytosis","Medullary thyroid cancer"],"answer":0,"explanation":"Carcinoid syndrome (serotonin-mediated): flushing + diarrhea + bronchospasm + right-sided heart valve disease (tricuspid regurgitation — serotonin inactivated by lung before left side). Requires liver metastases (bypass hepatic first-pass serotonin metabolism). Elevated urinary 5-HIAA confirms. Somatostatin analogue (octreotide/lanreotide) controls symptoms."},
  {"id":"q-short-bowel-1","dept":"uppergi","disease":"short-bowel","format":"mcq","stem":"After massive small bowel resection, the minimum length of residual small bowel to avoid permanent parenteral nutrition depends on which anatomical factor?","options":["<100cm with intact colon","<50cm without colon (end jejunostomy)","<150cm with intact ileocecal valve","Both A and B","<200cm regardless"],"answer":3,"explanation":"Short bowel syndrome: permanent TPN risk if <100cm with intact colon (colonic fluid/energy absorption) OR <50cm without colon (end jejunostomy). Ileocecal valve preservation important — slows transit, reduces diarrhea. Teduglutide (GLP-2 analogue) can reduce TPN dependence. Intestinal lengthening (STEP/Bianchi) for dilated bowel."},
  {"id":"q-radiation-enteritis-1","dept":"uppergi","disease":"radiation-enteritis","format":"mcq","stem":"A 65-year-old with history of pelvic radiotherapy for cervical cancer presents with recurrent small bowel obstruction and fistula. On examination, the terminal ileum is thickened. Management principle?","options":["Aggressive bowel resection","Minimal resection — bowel-conserving surgery with bypass preferred","Defunctioning ileostomy only","Conservative management with TPN","Steroids and immunosuppression"],"answer":1,"explanation":"Radiation enteritis: bowel is fragile, healing impaired — anastomotic leak rate high. Principles: bypass of affected segment rather than resection where possible; if resection needed, use unirradiated bowel for anastomosis; defunctioning stoma if high leak risk. Nutritional support (TPN/EN) essential pre-operatively."},
  {"id":"q-dcis-1","dept":"endocrine","disease":"dcis","format":"mcq","stem":"A 55-year-old has DCIS grade III, 25mm on MRI, ER positive. Wide local excision achieves R0. Adjuvant management?","options":["No further treatment","Radiotherapy to breast","Tamoxifen alone","Radiotherapy + tamoxifen","Mastectomy now required"],"answer":3,"explanation":"DCIS: WLE + radiotherapy reduces local recurrence by ~50% (EBCTCG). Adding tamoxifen (ER-positive) further reduces ipsilateral recurrence and risk of contralateral breast cancer (NSABP B-24). Grade III DCIS > 15–20mm: some centers prefer mastectomy. Sentinel lymph node biopsy not routine unless high grade, large, or mastectomy planned."},
  {"id":"q-phyllodes-1","dept":"endocrine","disease":"phyllodes","format":"mcq","stem":"A 38-year-old has a rapidly growing 5cm breast mass. Histology: phyllodes tumor, borderline, positive margins. Management?","options":["Observation only","Re-excision to achieve 1cm clear margins","Mastectomy","Radiotherapy","Tamoxifen"],"answer":1,"explanation":"Phyllodes tumor: wide excision with 1cm clear margins is the goal. Positive or close margins: re-excision. Borderline/malignant phyllodes with positive margins after re-excision: mastectomy. Adjuvant RT for malignant phyllodes with close margins. Chemotherapy for metastatic malignant phyllodes (ifosfamide-based). No hormonal therapy — ER negative."},
  {"id":"q-thyroid-ca-1","dept":"endocrine","disease":"thyroid-ca","format":"mcq","stem":"A 35-year-old has a 2.5cm papillary thyroid cancer with ipsilateral lymph node involvement (N1a). Management?","options":["Thyroid lobectomy only","Total thyroidectomy alone","Total thyroidectomy + central neck dissection + post-op RAI","Radiotherapy","Chemotherapy"],"answer":2,"explanation":"Papillary thyroid cancer T2N1aM0: total thyroidectomy + central neck dissection (level VI) + post-operative radioiodine ablation (RAI). RAI destroys remnant thyroid and micrometastases. Post-RAI: TSH suppression with levothyroxine. 10-year survival >95%. RAI not indicated for T1aN0 papillary cancer <1cm (low risk)."},
  {"id":"q-graves-1","dept":"endocrine","disease":"graves","format":"mcq","stem":"A 30-year-old with Graves' disease has failed two courses of antithyroid drugs and has large goitre with compressive symptoms. Preferred definitive treatment?","options":["Third course of carbimazole","Radioiodine","Total thyroidectomy","Potassium iodide alone","Beta-blockers long-term"],"answer":2,"explanation":"Definitive treatment for Graves': (1) radioiodine (preferred in most guidelines — simple, effective, ~85% success), (2) total thyroidectomy, (3) long-term ATD. Surgery preferred if: large goitre with compressive symptoms, active thyroid eye disease (RAI can worsen TED), pregnancy, patient preference, suspected malignancy. Pre-op: euthyroid with ATD + Lugol's iodine."},
  {"id":"q-mng-1","dept":"endocrine","disease":"mng","format":"mcq","stem":"A 60-year-old woman has a multinodular goitre with substernal extension causing dysphagia and positional dyspnea. CT shows tracheal deviation >1cm. Management?","options":["Observation and reassurance","Levothyroxine suppression","Total thyroidectomy","Radioiodine","Fine needle aspiration only"],"answer":2,"explanation":"Symptomatic MNG with compressive features (dysphagia, dyspnea, tracheal deviation): total thyroidectomy is indicated. Substernal extension: ensure CT to assess extent; anesthetic challenge (intubation may be difficult). Levothyroxine suppression: ineffective for large nodular goitres. RAI: can reduce volume 40–60% but slow. Surgery: rapid decompression."},
  {"id":"q-phpt-1","dept":"endocrine","disease":"phpt","format":"mcq","stem":"A 55-year-old has calcium 2.92, PTH 110 (elevated), T-score −2.7 at spine. 24h urine calcium elevated. Management?","options":["Increase fluid intake and observe","Cinacalcet (calcimimetic) alone","Parathyroidectomy","Bisphosphonates only","Vitamin D supplementation"],"answer":2,"explanation":"PHPT with symptoms/complications (osteoporosis T-score ≤−2.5, hypercalcemia >2.85, urinary calcium >10mmol/24h, age <50): parathyroidectomy is curative. Preoperative localization: sestamibi scan + USS. Minimally invasive parathyroidectomy (MIP) if single adenoma localized. Intraoperative PTH monitoring confirms cure (>50% fall)."},
  {"id":"q-shpt-1","dept":"endocrine","disease":"shpt","format":"mcq","stem":"A dialysis patient with secondary hyperparathyroidism has PTH 1100 pg/mL, calciphylaxis, and failed cinacalcet/calcitriol therapy. Treatment?","options":["Increase cinacalcet dose","Parathyroidectomy (subtotal or total + autotransplantation)","Kidney transplant alone","Bisphosphonates","Vitamin D supplementation"],"answer":1,"explanation":"Refractory secondary HPT (PTH >800 failing medical therapy, calciphylaxis, symptomatic bone disease): surgical parathyroidectomy. Options: subtotal (3.5 gland removal) vs total + forearm autotransplantation. Both equally effective; autotransplantation allows treatment of recurrence under local anesthesia."},
  {"id":"q-phaeo-1","dept":"endocrine","disease":"phaeochromocytoma","format":"mcq","stem":"Pre-operative preparation before adrenalectomy for phaeochromocytoma: what is the correct order?","options":["Beta-blockade first, then alpha-blockade","Alpha-blockade first (phenoxybenzamine), then beta-blockade if tachycardia","Beta-blockade only","No pre-op preparation needed","Calcium channel blocker only"],"answer":1,"explanation":"Alpha-blockade FIRST (phenoxybenzamine 10–20mg OD, titrated for 10–14 days) — prevents hypertensive crisis by blocking catecholamine-induced vasoconstriction. Add beta-blocker (propranolol) only AFTER adequate alpha-blockade to control reflex tachycardia. Beta-blockade alone without alpha → unopposed alpha effect → hypertensive crisis. Salt-loading + volume expansion also essential."},
  {"id":"q-conns-1","dept":"endocrine","disease":"conns","format":"mcq","stem":"A 45-year-old hypertensive patient has spontaneous hypokalemia (K+ 3.0), hypertension resistant to 3 drugs, and plasma aldosterone:renin ratio >30. Best initial diagnostic test?","options":["Adrenal CT immediately","CT-guided adrenal biopsy","Saline infusion test (aldosterone suppression)","24h urine catecholamines","Dexamethasone suppression test"],"answer":2,"explanation":"Conn's syndrome (primary hyperaldosteronism): screening = aldosterone:renin ratio >30 (>25–50 depending on units). Confirmatory test: saline infusion test (failure of aldosterone to suppress below 170pmol/L = confirmed). Then CT adrenal: adenoma vs bilateral hyperplasia. Adrenal vein sampling essential before surgery if CT equivocal or bilateral disease."},
  {"id":"q-cushings-adrenal-1","dept":"endocrine","disease":"cushings-adrenal","format":"mcq","stem":"A 40-year-old has Cushing's syndrome. MRI pituitary is normal. CT shows a 2.5cm left adrenal adenoma. ACTH is suppressed. Diagnosis?","options":["Cushing's disease (pituitary)","Ectopic ACTH syndrome","ACTH-independent adrenal Cushing's","Pseudo-Cushing's","Adrenocortical carcinoma"],"answer":2,"explanation":"ACTH-suppressed Cushing's = adrenal source (autonomous cortisol secretion suppresses pituitary ACTH). With a unilateral adrenal adenoma → adrenal Cushing's syndrome. Treatment: laparoscopic adrenalectomy of affected side. Post-op: steroid replacement until contralateral adrenal recovers (months to years). ACTH-dependent = pituitary or ectopic source."},
  {"id":"q-adrenocortical-ca-1","dept":"endocrine","disease":"adrenocortical-ca","format":"mcq","stem":"A 4cm adrenal mass has CT density >10HU, irregular borders, and delayed washout of 40%. What is the most likely diagnosis and next step?","options":["Adrenal adenoma — no action","Phaeochromocytoma — urine metanephrines","Adrenocortical carcinoma — surgical resection","Adrenal metastasis — biopsy","Myelolipoma — observation"],"answer":2,"explanation":"CT characteristics of ACC: >10 HU unenhanced, irregular margins, heterogeneous enhancement, delayed washout <50% (adenoma >50%). ACC: large (often >4cm), functional in 60% (cortisol ± androgens). Treatment: open adrenalectomy (laparoscopic acceptable for <8cm without invasion). Mitotane adjuvant for stage III-IV or R1 resection."},
  {"id":"q-adrenal-incidentaloma-1","dept":"endocrine","disease":"adrenal-incidentaloma","format":"mcq","stem":"A 3cm adrenal incidentaloma found on CT. Density 4HU, smooth margins, absolute washout 62%. What workup is required?","options":["Immediate adrenalectomy","No further workup — benign characteristics","Biochemical screen: 1mg DST, metanephrines, aldosterone:renin ratio; surveillance imaging","Biopsy","MRI for further characterization only"],"answer":2,"explanation":"All adrenal incidentalomas require biochemical workup: 1mg overnight DST (subclinical Cushing's), plasma/urine metanephrines (phaeochromocytoma), aldosterone:renin ratio if hypertensive (Conn's). CT density <10HU + absolute washout >60% = lipid-rich adenoma. Imaging follow-up at 6–12 months if no surgery. Size >4cm OR growing >1cm = surgery."},
  {"id":"q-insulinoma-1","dept":"endocrine","disease":"insulinoma","format":"mcq","stem":"A 35-year-old has insulinoma confirmed biochemically. CT pancreas is negative. Best localization technique?","options":["Repeat CT with pancreatic protocol","MRI pancreas","Endoscopic ultrasound (EUS)","Octreotide scan (SRS)","Selective arterial calcium stimulation test (SACST)"],"answer":2,"explanation":"EUS: sensitivity 90–95% for pancreatic insulinoma — best single test after negative CT. If EUS negative: SACST (calcium stimulates insulin secretion from the region containing the tumor, identifies feeding artery). Intraoperative USS is also highly sensitive. 90% of insulinomas are benign, solitary, and surgically curable by enucleation."},
  {"id":"q-men1-1","dept":"endocrine","disease":"men1","format":"mcq","stem":"MEN1 triad: which 3 glands?","options":["Pituitary + adrenal + thyroid","Parathyroid + pituitary + pancreatic islets (3 P's)","Parathyroid + adrenal + thyroid","Pancreas + pituitary + adrenal","Thyroid + pancreas + adrenal"],"answer":1,"explanation":"MEN1 (Wermer syndrome): Parathyroid (95%, most common; multiglandular hyperplasia) + Pituitary (40%, prolactinoma most common) + Pancreatic islets (50%, gastrinoma/insulinoma/VIPoma). Mutation: MEN1 tumor suppressor gene (11q13). Screening: calcium, PTH, gastrin, prolactin, fasting glucose annually from age 5. Surgery for PHPT: subtotal parathyroidectomy."},
  {"id":"q-men2-1","dept":"endocrine","disease":"men2","format":"mcq","stem":"A child is found to have RET proto-oncogene mutation (codon 634). What is the first cancer risk to address prophylactically?","options":["Parathyroid hyperplasia","Adrenal phaeochromocytoma","Medullary thyroid cancer","Parathyroid adenoma","Pancreatic NET"],"answer":2,"explanation":"MEN2A (RET codon 634): MTC (100% penetrance) + phaeochromocytoma (50%) + PHPT (20%). RET codon 634 = high risk → prophylactic thyroidectomy by age 5. Codon 918 = highest risk (MEN2B) → thyroidectomy in first 6 months of life. Screen for phaeochromocytoma before any surgery (urine/plasma metanephrines)."},
  {"id":"q-breast-abscess-1","dept":"endocrine","disease":"breast-abscess","format":"mcq","stem":"A 28-year-old breastfeeding mother has a 3cm fluctuant breast abscess. Temperature 38.5°C. Management?","options":["Antibiotics alone","Ultrasound-guided needle aspiration + oral antibiotics","Formal incision and drainage under GA","Cease breastfeeding immediately","Mammography"],"answer":1,"explanation":"Lactational breast abscess: ultrasound-guided aspiration + antibiotics (flucloxacillin/co-amoxiclav) — first-line; success rate ~80%, avoids surgical scar, allows continued breastfeeding. Repeat aspiration if re-accumulates (up to 3 times). I&D reserved for: failed aspiration, large abscess, or skin necrosis. Breastfeeding can continue; does not worsen outcome."},
  {"id":"q-trauma-lap-1","dept":"trauma","disease":"trauma-laparotomy","format":"mcq","stem":"A damage control laparotomy is performed for hemoperitoneum. After packing and temporary closure, when should planned relook occur?","options":["12 hours","24–48 hours when physiology corrected (lethal triad reversed)","72 hours","Immediately after CT","Only when patient is completely stable"],"answer":1,"explanation":"Damage control surgery (DCS): abbreviated initial surgery (hemorrhage control + contamination control), then ICU resuscitation to correct lethal triad (hypothermia, acidosis, coagulopathy). Planned relook at 24–48h when: temperature >36°C, pH >7.35, lactate normalizing, clotting corrected. Premature return to theater risks further hemodynamic instability."},
  {"id":"q-acs-1","dept":"trauma","disease":"acs","format":"mcq","stem":"Abdominal compartment syndrome: diagnostic threshold for intra-abdominal pressure?","options":[">12 mmHg","≥20 mmHg + new organ dysfunction","≥15 mmHg","≥25 mmHg","≥30 mmHg"],"answer":1,"explanation":"Intra-abdominal hypertension (IAH): IAP ≥12mmHg. Abdominal compartment syndrome (ACS): IAP ≥20mmHg + new or progressive organ dysfunction. Measure via urinary bladder transducer. Treatment: decompressive laparotomy + open abdomen management. IAP grades: I=12–15, II=16–20, III=21–25, IV>25 mmHg."},
  {"id":"q-splenic-trauma-1","dept":"trauma","disease":"splenic-trauma","format":"mcq","stem":"A 25-year-old has blunt abdominal trauma. CT shows grade III splenic laceration (<3cm depth, no vessel involvement). BP 130/80, HR 85. Management?","options":["Emergency splenectomy","Splenic artery embolization","Non-operative management (NOM) in HDU","Laparotomy and splenorrhaphy","Observation in ward only"],"answer":2,"explanation":"Hemodynamically stable splenic trauma grades I–III: NOM (non-operative management) is standard — success rate >85%. Grade III with blush or grades IV–V: consider angioembolization to reduce failure. NOM requires: HDU monitoring, serial hematocrit, no peritonism, available theater. Failure criteria: hemodynamic instability, peritonism, transfusion >4u."},
  {"id":"q-liver-trauma-1","dept":"trauma","disease":"liver-trauma","format":"mcq","stem":"Grade IV liver laceration (major parenchymal disruption 25–75% lobe). Patient transiently stable with CT showing active blush. Best management?","options":["NOM alone","Hepatic angioembolization","Damage control laparotomy: Pringle + packing","Total hepatectomy","Observation"],"answer":2,"explanation":"Grade IV liver injury with active blush in transiently stable patient: angioembolization may control arterial bleeding. If hemodynamically unstable or failure of embolization: damage control laparotomy — Pringle maneuver (hepatoduodenal ligament clamping) + perihepatic packing + planned relook. Grade I–III hemodynamically stable: NOM."},
  {"id":"q-bowel-trauma-1","dept":"trauma","disease":"bowel-trauma","format":"mcq","stem":"Hollow viscus injury is most commonly missed on initial CT after blunt abdominal trauma. Classic finding on CT suggesting bowel injury?","options":["Free fluid only","Mesenteric stranding + free air (pneumoperitoneum)","Splenic laceration","Liver contusion","Retroperitoneal hematoma"],"answer":1,"explanation":"Bowel/mesenteric injury: CT signs = pneumoperitoneum (free air), mesenteric hematoma/stranding, bowel wall thickening, free fluid without solid organ injury ('unexplained free fluid'). Seat belt sign + free fluid = bowel injury in 60%. Delayed diagnosis is common — serial abdominal exam + repeat CT if deteriorating."},
  {"id":"q-diaphragm-rupture-1","dept":"trauma","disease":"diaphragm-rupture","format":"mcq","stem":"A CXR after left-sided blunt thoracoabdominal trauma shows the NGT curling in the left hemithorax. Diagnosis?","options":["Hemothorax","Left diaphragmatic rupture with gastric herniation","Tension pneumothorax","Mediastinal widening","Ruptured spleen"],"answer":1,"explanation":"Left diaphragmatic rupture: classic CXR = NGT in left chest (stomach herniation). Left-sided >>right-sided (liver protects right). Mechanism: sudden rise in intra-abdominal pressure from deceleration. 30–40% missed initially. Repair: laparotomy (acute phase) or thoracotomy (chronic), primary suture of diaphragmatic defect."},
  {"id":"q-pelvic-fracture-1","dept":"trauma","disease":"pelvic-fracture","format":"mcq","stem":"A 30-year-old motorcyclist has unstable pelvic fracture (open-book), BP 80/60, HR 120, despite 2L IV fluids. Immediate life-saving step?","options":["CT pelvis","Emergency laparotomy","Pelvic binder/external fixator + resuscitative endovascular balloon occlusion (REBOA)","Bilateral femoral artery ligation","Retrograde urethrogram"],"answer":2,"explanation":"Hemodynamically unstable pelvic fracture: immediate pelvic binder (reduces pelvic volume) → REBOA zone III (infrarenal aortic occlusion) if available → angioembolization for arterial bleeding. Laparotomy only if other abdominal injury causing hemorrhage (FAST positive + peritonism). Pre-peritoneal pelvic packing is alternative to REBOA."},
  {"id":"q-wound-dehiscence-1","dept":"trauma","disease":"wound-dehiscence","format":"mcq","stem":"On day 6 post-laparotomy, wound discharges pink serous fluid. On exploration, burst abdomen with exposed bowel. Management?","options":["Wound dressing and antibiotics","Return to theater — mass closure with retention sutures","Secondary wound closure at bedside","Negative pressure wound therapy and wait","Conservative management"],"answer":1,"explanation":"Burst abdomen (complete dehiscence with evisceration): return to theater — mass closure with large interrupted nylon retention sutures (Jenkins rule: suture length to wound length ratio >4:1). Pre-op: cover bowel with moist saline packs, IV antibiotics. Identify predisposing factors (infection, poor nutrition, cough, too-tight closure)."},
  {"id":"q-penetrating-abdominal-1","dept":"trauma","disease":"penetrating-abdominal","format":"mcq","stem":"A stab wound to the epigastrium. Patient is hemodynamically stable. No peritonism. Which sign mandates immediate laparotomy without CT?","options":["Localized epigastric tenderness","Subcutaneous emphysema","Evisceration of omentum through wound","Stable vital signs after FAST","Shoulder tip pain"],"answer":2,"explanation":"Hard indications for immediate laparotomy in penetrating abdominal trauma: hemodynamic instability, peritonism, evisceration, gun shot wound. Stable GSW = mandatory laparotomy (high hollow viscus injury rate). Stable stab: local wound exploration; if peritoneum breached → diagnostic laparoscopy or laparotomy. Evisceration = always laparotomy."},
  {"id":"q-chest-trauma-1","dept":"trauma","disease":"chest-trauma","format":"mcq","stem":"Immediately after a road traffic accident, a patient has absent breath sounds on the right, tracheal deviation to the left, JVP distension, and hypotension. Next step?","options":["CXR","CT thorax","Immediate needle thoracostomy (2nd intercostal space, MCL)","Pericardiocentesis","IV fluids and observation"],"answer":2,"explanation":"Tension pneumothorax: needle thoracostomy (or finger thoracostomy) is immediate life-saving intervention — do NOT wait for CXR. Classic: absent breath sounds + tracheal deviation away + hypotension + distended JVP. After needle decompression → definitive chest drain (5th ICS, AAL). Cause: one-way valve mechanism in pleural space."},
  {"id":"q-burns-1","dept":"trauma","disease":"burns","format":"mcq","stem":"A 70kg adult has 40% TBSA burns. Parkland formula for first 24h fluid resuscitation?","options":["2mL × kg × %TBSA","4mL × kg × %TBSA in 24h (half in first 8h)","1L/h crystalloid","Colloid only (human albumin)","500mL boluses as needed"],"answer":1,"explanation":"Parkland formula: 4mL × kg × %TBSA burn (exclude superficial burns) in first 24h. Half in first 8h from time of burn (not from time of arrival), half over next 16h. Use Hartmann's/lactated Ringer's. Titrate to urine output 0.5–1mL/kg/h. 24h to 48h: colloid (human albumin 5%) to replace evaporative losses."},
  {"id":"q-compartment-limb-1","dept":"trauma","disease":"compartment-limb","format":"mcq","stem":"Compartment syndrome: at what delta pressure (diastolic BP minus compartment pressure) should fasciotomy be performed?","options":["<40 mmHg","<30 mmHg","<20 mmHg","<10 mmHg",">50 mmHg"],"answer":1,"explanation":"Compartment syndrome: fasciotomy indicated when delta pressure (diastolic BP – compartment pressure) <30 mmHg, OR compartment pressure >30 mmHg, OR when clinical diagnosis is clear (pain with passive stretch, tense compartment, paraesthesia). Do not wait for paralyzis (late sign). Lower leg: 4-compartment fasciotomy via 2 incisions."},
  {"id":"q-renal-trauma-1","dept":"trauma","disease":"renal-trauma","format":"mcq","stem":"Grade IV renal laceration (collecting system injury) with stable hemodynamics. Urinoma on CT. Management?","options":["Immediate nephrectomy","NOM: ureteral stent + percutaneous drain","Embolization","Observation without drain","Open repair"],"answer":1,"explanation":"Stable grade IV renal injury with urinoma: minimally invasive management — ureteral stent (retrograde) to divert urine + percutaneous drain of urinoma. Nephrectomy only for: hemodynamic instability, grade V injury with destroyed kidney, failed minimal invasive management. NOM success rate >90% for grade I-III, and high for grade IV if stable."},
  {"id":"q-traumatic-brain-1","dept":"trauma","disease":"traumatic-brain","format":"mcq","stem":"A 30-year-old with lucid interval after head injury deteriorates rapidly with a fixed dilated pupil and contralateral hemiplegia. CT shows biconvex hyperdense lesion. Diagnosis and treatment?","options":["Subdural hematoma — craniotomy","Extradural hematoma — emergency burr holes/craniotomy","Subarachnoid hemorrhage — nimodipine","Diffuse axonal injury — ICP monitoring","Cerebral contusion — observation"],"answer":1,"explanation":"Extradural hematoma (EDH): biconvex hyperdense lesion on CT (does not cross suture lines); middle meningeal artery injury; classic lucid interval. Fixed dilated pupil = ipsilateral uncal herniation. Emergency craniotomy and hematoma evacuation. Do not delay for neurosurgery referral if patient deteriorating — emergency burr holes can be life-saving."},
  {"id":"q-renal-tx-1","dept":"transplant","disease":"renal-tx","format":"mcq","stem":"A kidney transplant recipient has anuria on day 1. Doppler USS shows absent arterial flow. Immediate management?","options":["IV fluids only","Increase tacrolimus","Emergency surgical re-exploration for renal artery thrombosis","Hemodialysis and wait","CT angiography first"],"answer":2,"explanation":"Renal artery thrombosis post-transplant: surgical emergency. Absent flow on Doppler → immediate surgical re-exploration. Window for salvage <6h. Thrombectomy may restore flow; graft loss common if delayed. Causes: technical anastomotic problem, hyperacute rejection, hypercoagulable state. Do not delay for further imaging."},
  {"id":"q-pancreas-tx-1","dept":"transplant","disease":"pancreas-tx","format":"mcq","stem":"Most common indication for simultaneous pancreas-kidney (SPK) transplant?","options":["Type 1 diabetes with end-stage renal disease","Type 2 diabetes with end-stage renal disease","Type 1 diabetes with normal renal function","Chronic pancreatitis with ESRD","Islet cell failure after total pancreatectomy"],"answer":0,"explanation":"SPK transplant: primary indication = type 1 diabetes mellitus + end-stage renal disease (GFR <20mL/min). Advantages: single operation, immunological synergy (shared donor), insulin independence (80% at 5 years). PAK (pancreas after kidney): T1DM with functioning prior renal transplant. PTA (pancreas transplant alone): T1DM with hypoglycemia unawareness + normal renal function."},
  {"id":"q-small-bowel-tx-1","dept":"transplant","disease":"small-bowel-tx","format":"mcq","stem":"Primary indication for intestinal transplantation in adults?","options":["Crohn's disease refractory to all medications","Intestinal failure-associated liver disease (IFALD) on long-term TPN","Short bowel syndrome manageable with TPN","Type 3 intestinal failure post-radiation","Mesenteric ischemia with residual bowel"],"answer":1,"explanation":"Small bowel transplantation: reserved for intestinal failure patients who CANNOT continue TPN due to: IFALD (TPN-associated liver disease progressing to cirrhosis), TPN access loss (thrombosis of all central veins), recurrent line-related sepsis. High rejection rate (acute/chronic); lifelong tacrolimus. 5-year graft survival ~50%."},
  {"id":"q-ldh-1","dept":"transplant","disease":"living-donor-hepatectomy","format":"mcq","stem":"Minimum future liver remnant (FLR) required for a living donor right hepatectomy?","options":["20%","30%","40%","50%","60%"],"answer":2,"explanation":"Living donor safety: FLR must be ≥40% of total liver volume to ensure donor safety and prevent post-hepatectomy liver failure. Right lobe donation (segments V-VIII) provides 55–70% of liver volume to recipient. Donor mortality risk: 0.1–0.5% for right hepatectomy. Volumetric CT is essential pre-op. FLR <30% = unsafe for donor."},
  {"id":"q-pneumothorax-1","dept":"thoracic","disease":"pneumothorax","format":"mcq","stem":"A 22-year-old tall thin male has a spontaneous left pneumothorax with 3cm rim on CXR. Mildly breathless. Best management?","options":["Observation only for 24h","Supplemental O2 and discharge","Needle aspiration","Chest drain (14Fr) + water seal","Surgical VATS pleurodesis immediately"],"answer":2,"explanation":"Primary spontaneous pneumothorax ≥2cm or symptomatic: needle aspiration first (50–60% success, BTS/ERS 2023). If aspiration fails: small-bore chest drain (8–14Fr). Large-bore drains not required for simple PTX. Second episode or persistent air leak: VATS bullectomy + pleurodesis. Supplemental O2 speeds reabsorption but alone insufficient for >2cm."},
  {"id":"q-empyema-1","dept":"thoracic","disease":"empyema","format":"mcq","stem":"A patient has exudative pleural effusion with pH <7.2, glucose <2.2mmol/L, and LDH >1000. Frank pus on aspiration. Stage?","options":["Exudative — simple drainage","Fibrinopurulent — drain + intrapleural fibrinolytics (tPA/DNase)","Organized — surgical decortication","Stage I — observation","Transudative — diuretics"],"answer":1,"explanation":"BTS empyema staging: Stage I (exudative, pH>7.2, glucose>2.2) = simple pleural drainage. Stage II (fibrinopurulent, pH<7.2, glucose<2.2, or frank pus) = chest drain + intrapleural tPA 10mg + DNase 5mg alternating for 3 days (MIST2 trial). Stage III (organized/thick peel) = VATS decortication. This patient = Stage II."},
  {"id":"q-mesothelioma-1","dept":"thoracic","disease":"mesothelioma","format":"mcq","stem":"A 68-year-old ex-shipyard worker has unilateral pleural effusion, pleural thickening, and chest pain. Pleural biopsy: mesothelioma. Most important exposure history?","options":["Tobacco smoking","Asbestos","Silica dust","Radon gas","Arsenic"],"answer":1,"explanation":"Malignant pleural mesothelioma: asbestos exposure (especially amphibole fibers: crocidolite/amosite) is the primary cause in >80%. Latency period 30–50 years. Legal implications — Industrial Injuries Disablement Benefit, mesothelioma compensation scheme. Histology: epithelioid (best prognosis), sarcomatoid, biphasic. Calretinin + WT-1 positive."},
  {"id":"q-thymoma-1","dept":"thoracic","disease":"thymoma","format":"mcq","stem":"A 45-year-old has anterior mediastinal mass and ptosis, diplopia, and fatiguable weakness. Acetylcholine receptor antibodies positive. Diagnosis?","options":["Lymphoma","Teratoma","Thymoma with myasthenia gravis","Thyroid mass","Pericardial cyst"],"answer":2,"explanation":"Thymoma + myasthenia gravis: 30–40% of thymomas present with MG; conversely, 15% of MG patients have thymoma. Anterior mediastinal mass = 4T's: Thymoma, Teratoma, Thyroid, Terrible lymphoma. Thymoma treatment: thymectomy (VATS or sternotomy) — even in MG without thymoma, thymectomy improves remission. Pre-op MG management with pyridostigmine."},
  {"id":"q-oesoph-perf-1","dept":"thoracic","disease":"oesophageal-perforation","format":"mcq","stem":"Iatrogenic esophageal perforation during upper endoscopy. Small contained perforation, no mediastinitis. Patient stable. Management?","options":["Immediate open repair","Conservative: nil orally, IV antibiotics, nutritional support","Esophagectomy","Esophageal stent only","Observation without antibiotics"],"answer":1,"explanation":"Iatrogenic perforation: small, contained, no mediastinitis, stable → conservative management (NPO + IV antibiotics + nutritional support via NGT/TPN) — success rate 70–80% in selected cases. Endoscopic stenting for contained leaks. Surgery (primary repair) for: late presentation, large perforation, mediastinitis, failed conservative, distal obstruction. Boerhaave (spontaneous) usually requires surgery."},
  {"id":"q-haemothorax-1","dept":"thoracic","disease":"haemothorax","format":"mcq","stem":"Traumatic hemothorax: 1500mL drained immediately on chest tube insertion. Indication for emergency thoracotomy?","options":[">1000mL initial drain","≥1500mL initial drain OR ongoing blood loss >200mL/h for 3–4h","Any hemothorax >500mL","Signs of mediastinal shift","Bilateral hemothorax"],"answer":1,"explanation":"Massive hemothorax: initial drainage ≥1500mL OR ongoing 200mL/h for 3–4h (or >1500mL/24h) = indication for operative intervention (VATS or thoracotomy). Retained hemothorax (failed drain): VATS evacuation within 7 days to prevent empyema. Chest drain alone adequate if drainage <1500mL initial and ongoing losses minimal."},
  {"id":"q-lung-abscess-1","dept":"thoracic","disease":"lung-abscess","format":"mcq","stem":"A 60-year-old alcoholic has a 6cm right lower lobe cavity with air-fluid level on CXR. No organisms on sputum. Most appropriate initial management?","options":["Immediate surgery","Bronchoscopy + prolonged IV antibiotics (6 weeks)","CT-guided drainage","Antifungals","Bronchoscopic lavage only"],"answer":1,"explanation":"Primary lung abscess: prolonged IV antibiotics (4–6 weeks) — amoxicillin-clavulanate or clindamycin (anaerobic cover essential). Bronchoscopy to exclude obstructing lesion and obtain culture. Surgery (lobectomy) reserved for: failed medical treatment >3 months, massive hemoptysis, tumor obstruction, or rupture. CT-guided drainage if inaccessible to bronchoscopy."},
  {"id":"q-mediastinal-mass-1","dept":"thoracic","disease":"mediastinal-mass","format":"mcq","stem":"A posterior mediastinal mass in a 10-year-old on CXR. MRI shows a dumbbell-shaped lesion extending through neural foramen. Most likely diagnosis?","options":["Lymphoma","Thymoma","Neuroblastoma or ganglioneuroma (neurogenic tumor)","Teratoma","Pericardial cyst"],"answer":2,"explanation":"Posterior mediastinal masses: predominantly neurogenic tumors (80%): neuroblastoma/ganglioneuroma (children), schwannoma/neurofibroma (adults). Dumbbell extension through intervertebral foramen is pathognomonic. Neurosurgical + thoracic surgery co-operation. Middle mediastinum: lymphoma, cysts. Anterior: 4Ts (thymoma, teratoma, thyroid, terrible lymphoma)."},
  {"id":"q-pectus-1","dept":"thoracic","disease":"pectus","format":"mcq","stem":"A 16-year-old has pectus excavatum with Haller index 3.8 and exercise intolerance. ECG shows RV strain. Indication for surgery?","options":["Cosmetic concern alone","Haller index >3.25 + functional impairment or cardiac/pulmonary involvement","Haller index >2 only","Age <10 years","All pectus excavatum"],"answer":1,"explanation":"Pectus excavatum repair (Nuss procedure — MIRPE): indicated for Haller index ≥3.25 (CI = transverse diameter/AP diameter; normal <2.5) plus functional impairment (exercise intolerance, cardiac compression, paradoxical movement). Bar removal at 3 years. Ravitch procedure (open) for severe/asymmetric. Cosmetic indication alone is not routinely funded."},
  {"id":"q-lung-carcinoid-1","dept":"thoracic","disease":"lung-carcinoid","format":"mcq","stem":"Typical pulmonary carcinoid 2cm in right lower lobe, no lymph nodes, in a 40-year-old. Treatment?","options":["Observation","Somatostatin analogue alone","Lobectomy with systematic nodal dissection","Stereotactic body radiotherapy","Chemotherapy"],"answer":2,"explanation":"Typical pulmonary carcinoid (low-grade NET, <2 mitoses/2mm², no necrosis): surgical resection is curative — lobectomy with nodal sampling/dissection. Sleeve resection for central tumors (lung-conserving). 5-year survival >90%. Atypical carcinoid (>2 mitoses): more aggressive, lobectomy + mediastinal nodal dissection. No adjuvant therapy for typical carcinoid with N0 disease."},
  {"id":"q-femoral-hernia-1","dept":"hernia","disease":"femoral-hernia","format":"mcq","stem":"A 70-year-old woman has a tense, irreducible groin lump below and lateral to the pubic tubercle. Diagnosis and urgency?","options":["Inguinal hernia — elective repair","Femoral hernia — urgent repair (high strangulation risk)","Lymph node — observe","Saphena varix — compression","Lipoma — remove electively"],"answer":1,"explanation":"Femoral hernia: below and lateral to pubic tubercle (inguinal hernia is above and medial). Femoral hernias have a 40% strangulation rate (narrow neck of femoral canal) — all femoral hernias should be repaired urgently. Approach: low (Lockwood), high (McEvedy), or laparoscopic (TEP/TAPP). Never reduce a femoral hernia in elderly women without surgical assessment — risk of reduce-and-miss strangulation."},
  {"id":"q-umbilical-hernia-1","dept":"hernia","disease":"umbilical-hernia","format":"mcq","stem":"A 40-year-old has a 3cm umbilical hernia defect with recurrent incarceration episodes. Repair technique?","options":["Primary suture repair","Mesh repair (open sublay or laparoscopic IPOM)","Observation only","Truss fitting","Reduce and observe"],"answer":1,"explanation":"Umbilical hernia >1cm or recurrent incarceration: mesh repair. Open sublay (preperitoneal/retromuscular mesh) or laparoscopic IPOM. Recurrence rate: suture alone 10–30%; mesh 1–5%. Primary suture acceptable for small (<1cm) defects in young patients. Recurrent umbilical hernia = mesh regardless of size."},
  {"id":"q-incisional-hernia-1","dept":"hernia","disease":"incisional-hernia","format":"mcq","stem":"A 55-year-old has a 6cm incisional hernia post-midline laparotomy. Loss of domain present on CT. Preferred repair technique?","options":["Primary suture repair","Open retromuscular (Rives-Stoppa) mesh repair","Laparoscopic IPOM","Tissue repair only","Observation"],"answer":1,"explanation":"Incisional hernia >4cm: open retromuscular (Rives-Stoppa) or transversus abdominis release (TAR) with large mesh overlap is gold standard — lowest recurrence (<5%). IPOM for smaller hernias or multiple recurrences. Primary suture alone for incisional hernias has 40–50% recurrence. Loss of domain: component separation (CS) + TAR to achieve closure without tension."},
  {"id":"q-epigastric-hernia-1","dept":"hernia","disease":"epigastric-hernia","format":"mcq","stem":"A 30-year-old has a small (0.8cm) painful epigastric midline lump. No reducibility, tender. Most likely content?","options":["Bowel","Omentum","Pre-peritoneal fat","Peritoneal sac with fluid","Empty — no content"],"answer":2,"explanation":"Epigastric hernias: 70–80% contain pre-peritoneal fat only (no true peritoneal sac). Pain disproportionate to small size = incarcerated pre-peritoneal fat causing ischemic pain. Small (<1cm), asymptomatic: observation acceptable. Symptomatic regardless of size: repair. Suture repair for small defects; mesh for ≥1cm."},
  {"id":"q-strangulated-hernia-1","dept":"hernia","disease":"strangulated-hernia","format":"mcq","stem":"Intraoperatively for a strangulated inguinal hernia, the bowel is dark purple. After releasing the neck and warming with saline, the bowel does not recover. Next step?","options":["Replace bowel in abdomen and observe","Bowel resection + primary anastomosis","Damage control: close and return to theater","Hartmann's procedure","Bowel stapling without resection"],"answer":1,"explanation":"Strangulated hernia with non-viable bowel: resection with primary anastomosis (if no significant contamination and patient stable). Assessment of viability: pink color + peristalsis + arterial pulsation = viable; purple/black + no peristalsis = non-viable → resect. Risk of anastomotic leak with contamination or compromised patient: Hartmann's or stoma."},
  {"id":"q-parastomal-hernia-1","dept":"hernia","disease":"parastomal-hernia","format":"mcq","stem":"A patient with a permanent end colostomy has a large symptomatic parastomal hernia. Most durable repair option?","options":["Primary fascial repair","Local suture repair around stoma","Stoma relocation","Laparoscopic keyhole mesh (Sugarbaker or sandwich technique)","Observation with a hernia belt"],"answer":3,"explanation":"Parastomal hernia repair: laparoscopic mesh repair (Sugarbaker technique — mesh with lateral stoma passage) has lowest recurrence (~10–20%) compared to primary repair (>50% recurrence) or relocation (30–50%). PREVENT trial: prophylactic mesh at colostomy formation significantly reduces parastomal hernia incidence. Reserve surgery for: obstruction, strangulation, skin ulceration, or appliance problems."},
  {"id":"q-spigelian-hernia-1","dept":"hernia","disease":"spigelian-hernia","format":"mcq","stem":"A 50-year-old has intermittent lateral abdominal pain at the linea semilunaris below the arcuate line. Palpation reveals a defect. What is the key investigation?","options":["CT abdomen","Barium enema","Ultrasound of the abdominal wall","MRI","Diagnostic laparoscopy immediately"],"answer":2,"explanation":"Spigelian hernia: occurs through defect in the spigelian aponeurosis at the lateral border of rectus (linea semilunaris), below the arcuate line. Often interparietal (between layers) — not visible on surface, easily missed clinically. USS or CT confirms defect. High incarceration risk → repair all diagnosed Spigelian hernias. Laparoscopic TEP/TAPP or open mesh repair."},
  {"id":"q-obturator-hernia-1","dept":"hernia","disease":"obturator-hernia","format":"mcq","stem":"An 80-year-old thin woman has bowel obstruction with inner thigh pain and positive Howship-Romberg sign. Diagnosis?","options":["Femoral hernia","Obturator hernia","Lumbar hernia","Sciatic hernia","Inguinal hernia"],"answer":1,"explanation":"Obturator hernia: rare, elderly thin women (loses fat pad in obturator canal). Howship-Romberg sign = pain radiating down inner thigh (medial aspect, obturator nerve compression) on hip extension/internal rotation. Diagnosis: CT confirms. Treatment: emergency surgery (high strangulation/SBO risk). Richter's hernia common at this site."},
  {"id":"q-retroperitoneal-sarcoma-1","dept":"hernia","disease":"retroperitoneal-sarcoma","format":"mcq","stem":"A 55-year-old has a 15cm retroperitoneal mass. CT shows heterogeneous fat density consistent with well-differentiated liposarcoma. MDM2/CDK4 amplification on FISH. Management?","options":["Core biopsy before surgery","Neoadjuvant chemotherapy first","Preoperative core biopsy rarely needed — proceed to resection at sarcoma center","Radiotherapy alone","Observation with 6-monthly CT"],"answer":2,"explanation":"Retroperitoneal sarcoma: biopsy is generally NOT required if imaging is diagnostic (large fat-density mass with MDM2 amplification = WDLPS) — proceed to surgical resection at specialised sarcoma center. Preoperative biopsy: only if histology will change management (e.g., lymphoma suspected, palliative chemotherapy planned). Surgery: complete resection is the only curative option; wide margins difficult given retroperitoneal anatomy."},
  {"id":"q-bcc-1","dept":"softtissue","disease":"bcc","format":"mcq","stem":"A 1.2cm BCC on the nose with poorly defined borders. Best treatment?","options":["Cryotherapy","Simple excision with 4mm margins","Mohs micrographic surgery","Radiotherapy","Topical 5-fluorouracil"],"answer":2,"explanation":"High-risk BCC (face, nose, ears, periorbital): Mohs micrographic surgery (MMS) offers highest cure rates (>99%) and maximal tissue conservation — essential for cosmetically sensitive areas and sites with high recurrence risk. Standard excision with 4mm margins for low-risk BCCs on trunk/limbs. Radiotherapy for inoperable/elderly. Vismodegib (hedgehog inhibitor) for advanced/metastatic BCC."},
  {"id":"q-scc-skin-1","dept":"softtissue","disease":"scc-skin","format":"mcq","stem":"A 2cm SCC on the lower lip in a 70-year-old. Clinically N0 neck. High-risk features (>2mm depth, perineural invasion). Next step?","options":["Wide excision alone","Wide excision + sentinel lymph node biopsy","Wide excision + elective neck dissection","Radiotherapy only","Chemotherapy first"],"answer":2,"explanation":"High-risk cutaneous SCC (>2mm Breslow, perineural/lymphovascular invasion, immunosuppressed, head/neck): sentinel lymph node biopsy (SLNB) or elective neck dissection to assess/manage regional nodes. Positive SLNB: completion lymph node dissection + adjuvant radiotherapy. Cemiplimab (anti-PD1) for locally advanced or metastatic cSCC."},
  {"id":"q-hidradenitis-1","dept":"softtissue","disease":"hidradenitis","format":"mcq","stem":"Hurley stage III hidradenitis suppurativa (diffuse disease, multiple tracts). Best surgical management?","options":["Incision and drainage","Deroofing alone","Wide radical excision down to fascia + secondary healing","Anti-TNF (adalimumab) only","Laser treatment"],"answer":2,"explanation":"Hurley III HS: wide radical excision with clear margins (remove entire affected hair-bearing skin down to deep fascia). Recurrence lowest with wide excision compared to deroofing. Healing by secondary intention or skin grafting. Adalimumab (PIONEER trials): reduces disease severity for Hurley I-II; does not cure Hurley III. Combine: pre-op adalimumab to reduce inflammation, then surgery."},
  {"id":"q-liposarcoma-1","dept":"softtissue","disease":"liposarcoma","format":"mcq","stem":"MDM2 amplification on FISH differentiates which subtypes?","options":["Myxoid liposarcoma from dedifferentiated","Well-differentiated / dedifferentiated liposarcoma from other fat tumors","Pleomorphic liposarcoma from fibrosarcoma","All liposarcomas","Lipoma from liposarcoma in all cases"],"answer":1,"explanation":"MDM2/CDK4 amplification (12q13-15): specific for WDLPS and DDLPS — differentiates them from benign lipoma and other sarcomas. Myxoid liposarcoma: FUS-DDIT3 translocation t(12;16). Pleomorphic liposarcoma: complex karyotype, no specific translocation. MDM2 FISH is the key diagnostic test when cytology/histology is equivocal."},
  {"id":"q-leiomyosarcoma-1","dept":"softtissue","disease":"leiomyosarcoma","format":"mcq","stem":"A 50-year-old has a uterine leiomyosarcoma with IVC involvement at segment II. Who should perform this resection?","options":["General surgeon alone","Gynecological oncologist alone","Specialist soft tissue sarcoma center with vascular/hepatobiliary surgeon","Cardiac surgery team","Palliative resection not advised"],"answer":2,"explanation":"IVC leiomyosarcoma: requires specialist sarcoma center with multidisciplinary involvement — vascular surgeon (IVC reconstruction) + HPB/hepatic surgeon (if hepatic veins involved). IVC segments: I (infrarenal), II (renal veins to hepatic veins), III (suprarenal, suprarenal to hepatic veins). Pre-op: IVC cavogram + renal function assessment. Complete resection offers best survival."},
  {"id":"q-desmoid-1","dept":"softtissue","disease":"desmoid","format":"mcq","stem":"A 30-year-old with FAP has a post-colectomy mesenteric desmoid tumor causing SBO. First systemic treatment?","options":["Surgical resection","Sorafenib (tyrosine kinase inhibitor)","Conventional cytotoxic chemotherapy","Radiotherapy","Sulindac + tamoxifen"],"answer":1,"explanation":"Desmoid tumor (aggressive fibromatosis): first-line systemic therapy in progressive/unresectable disease = sorafenib (Alliance A091105 trial: PFS improvement vs placebo). Sulindac ± tamoxifen for FAP-associated desmoids (limited evidence). Surgery: high recurrence (40–85%) + risk of bowel injury in mesenteric location. Radiotherapy for accessible tumors. Active surveillance for stable asymptomatic tumors."},
  {"id":"q-merkel-1","dept":"softtissue","disease":"merkel-cell","format":"mcq","stem":"Merkel cell carcinoma: what determines adjuvant treatment after WLE with clear margins and positive SLNB?","options":["Observation only","Completion lymph node dissection ± radiotherapy","Chemotherapy (platinum-based) only","Avelumab immunotherapy","No further treatment needed"],"answer":1,"explanation":"Merkel cell carcinoma with positive SLNB: completion lymph node dissection + adjuvant radiotherapy to primary site and regional nodes. Immunotherapy (avelumab, pembrolizumab) for: stage IV (metastatic) disease — JAVELIN Merkel 200 trial: avelumab OS benefit. MCC is immunogenic (Merkel cell polyomavirus + UV-induced); responds well to checkpoint inhibitors."},
  {"id":"q-kaposi-1","dept":"softtissue","disease":"kaposi","format":"mcq","stem":"AIDS-related Kaposi sarcoma with 20 cutaneous lesions and no visceral involvement. CD4 count 80. Best initial management?","options":["Surgical excision of all lesions","Radiotherapy to all lesions","Antiretroviral therapy (ART) alone","Liposomal doxorubicin + ART","Interferon-alpha"],"answer":2,"explanation":"AIDS-related KS: ART is the cornerstone — immune reconstitution (raising CD4 count) causes regression in 50% of limited cutaneous KS. Systemic chemotherapy (liposomal doxorubicin) for: visceral involvement, extensive cutaneous disease, rapid progression, or immune reconstitution fails. Local therapies (RT, intralesional vinblastine) for isolated symptomatic lesions."},
  {"id":"q-atls-survey-1","dept":"trauma","disease":"atls-primary-survey","format":"mcq","stem":"Modern trauma primary surveys add a step before 'A' for airway. In PHTLS/UK courses this is 'X'. In ATLS it is written '<C>'. What does this pre-step represent?","options":["Cervical spine assessment","eXsanguinating / Catastrophic external hemorrhage control","Chest decompression","Consciousness assessment","C-spine CT clearance"],"answer":1,"explanation":"X-ABCDE (PHTLS, TCCC, UK trauma) and <C>ABCDE (ATLS 10/11) both place hemorrhage control FIRST: X = eXsanguinating hemorrhage; <C> = Catastrophic hemorrhage. Tourniquet for limb bleeding; wound packing for junctional. This pre-step is performed before airway. Key distinction: in X-ABCDE, 'C' retains its original meaning of Circulation."},
  {"id":"q-atls-shock-1","dept":"trauma","disease":"atls-haemorrhagic-shock","format":"mcq","stem":"A trauma patient has HR 128, SBP 88, GCS 12, RR 32, and base deficit −8. Which ATLS shock class?","options":["Class I","Class II","Class III","Class IV","Neurogenic shock"],"answer":2,"explanation":"Class III hemorrhagic shock: 30–40% blood volume loss (1500–2000mL). HR >120, SBP <90, GCS 11–13, RR 30–40, BD −6 to −10. Requires blood transfusion + MTP activation. Class IV: HR >140, SBP <70, GCS <10."},
  {"id":"q-atls-spinal-1","dept":"trauma","disease":"atls-spinal-trauma","format":"mcq","stem":"NEXUS criteria: which combination allows clinical clearance of the C-spine without imaging?","options":["GCS 15 + no midline tenderness alone","All 5 criteria negative: no tenderness, no neuro deficit, normal alertness, no intoxication, no distracting injury","Normal GCS + no intoxication","Age <65 + no mechanism","Normal plain X-ray C-spine"],"answer":1,"explanation":"NEXUS: ALL 5 criteria must be negative to clinically clear the C-spine. 1) No posterior midline C-spine tenderness. 2) No focal neurological deficit. 3) Normal alertness. 4) No intoxication. 5) No painful distracting injury. Sensitivity 99.6%. Any single positive criterion = CT C-spine required."},
  {"id":"q-atls-airway-1","dept":"trauma","disease":"atls-airway","format":"mcq","stem":"After 3 failed RSI attempts in a trauma patient, SpO₂ is falling to 78%. Bag-mask ventilation is also failing. ATLS 11 immediate next step?","options":["Try a 4th intubation attempt with a smaller tube","Insert a nasopharyngeal airway","Declare CICO — immediate scalpel-finger-bougie cricothyroidotomy","Insert LMA and call for senior help","Needle cricothyroidotomy with IV cannula"],"answer":2,"explanation":"CICO (Cannot Intubate Cannot Oxygenate): declare CICO after 3 failed attempts + failed supraglottic oxygenation. Immediate scalpel-finger-bougie cricothyroidotomy (ATLS 11 preferred technique): 4cm vertical skin incision → stab through cricothyroid membrane → finger to confirm → bougie → 6.0 ETT → inflate → ETCO₂. No further laryngoscopy attempts."},
  {"id":"q-congenital-diaphragmatic-hernia-1","dept":"thoracic","disease":"congenital-diaphragmatic-hernia","format":"mcq","stem":"A 55-year-old has an incidental rounded right-sided anterior cardiophrenic opacity on CXR; CT shows transverse colon herniating through an anterior retrosternal diaphragmatic defect. Which congenital diaphragmatic hernia is this?","options":["Bochdalek hernia (posterolateral)","Morgagni hernia (anterior retrosternal)","Sliding hiatus hernia","Traumatic diaphragmatic rupture","Diaphragmatic eventration"],"answer":1,"explanation":"Morgagni hernia: anterior retrosternal defect at the foramen of Morgagni; ~90% right-sided (the pericardium shields the left foramen); usually asymptomatic and found incidentally in adults. Bochdalek is posterolateral, mostly left-sided, and typically presents in neonates with pulmonary hypoplasia. Adult Morgagni is repaired (commonly laparoscopically) to prevent colonic obstruction/strangulation. Distinct from hiatus hernia, which herniates through the oesophageal hiatus."}
];
